INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Oktopusse haben drei Herzen.","isTrue":"true","explanation":"Zwei Kiemenherzen pumpen Blut zu den Kiemen, ein Hauptherz pumpt es durch den Körper."},"en":{"statement":"Octopuses have three hearts.","isTrue":"true","explanation":"Two branchial hearts pump blood to the gills, while a main heart pumps it through the body."},"es":{"statement":"Los pulpos tienen tres corazones.","isTrue":"true","explanation":"Dos corazones branquiales bombean sangre a las branquias, un corazón principal la bombea por el cuerpo."},"fr":{"statement":"Les pieuvres ont trois cœurs.","isTrue":"true","explanation":"Deux cœurs branchiaux pompent le sang vers les branchies, un cœur principal le pompe dans le corps."},"it":{"statement":"I polpi hanno tre cuori.","isTrue":"true","explanation":"Due cuori branchiali pompano sangue alle branchie, un cuore principale lo pompa nel corpo."},"nl":{"statement":"Octopussen hebben drie harten.","isTrue":"true","explanation":"Twee kieuwenharten pompen bloed naar de kieuwen, één hoofdhart pompt het door het lichaam."},"pl":{"statement":"Ośmiornice mają trzy serca.","isTrue":"true","explanation":"Dwa serca skrzelowe pompują krew do skrzeli, a jedno główne serce pompuje ją przez ciało."},"pt":{"statement":"Os polvos têm três corações.","isTrue":"true","explanation":"Dois corações branquiais bombeiam sangue para as brânquias, um coração principal bombeia-o pelo corpo."},"tr":{"statement":"Ahtapotların üç kalbi vardır.","isTrue":"true","explanation":"İki solungaç kalbi kanı solungaçlara, bir ana kalp ise vücuda pompalar."},"ar":{"statement":"الأخطبوط لديه ثلاثة قلوب.","isTrue":"true","explanation":"قلبان خياشيميان يضخان الدم إلى الخياشيم، وقلب رئيسي يضخه عبر الجسم."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Goldfische haben ein Gedächtnis von nur 3 Sekunden.","isTrue":"false","explanation":"Goldfische können sich monatelang an Dinge erinnern — der 3-Sekunden-Mythos ist falsch."},"en":{"statement":"Goldfish have a memory of only 3 seconds.","isTrue":"false","explanation":"Goldfish can remember things for months — the 3-second myth is completely false."},"es":{"statement":"Los peces dorados tienen una memoria de solo 3 segundos.","isTrue":"false","explanation":"Los peces dorados pueden recordar cosas durante meses — el mito de los 3 segundos es falso."},"fr":{"statement":"Les poissons rouges ont une mémoire de seulement 3 secondes.","isTrue":"false","explanation":"Les poissons rouges peuvent se souvenir de choses pendant des mois — le mythe des 3 secondes est faux."},"it":{"statement":"I pesci rossi hanno una memoria di soli 3 secondi.","isTrue":"false","explanation":"I pesci rossi possono ricordare le cose per mesi — il mito dei 3 secondi è falso."},"nl":{"statement":"Goudvissen hebben een geheugen van slechts 3 seconden.","isTrue":"false","explanation":"Goudvissen kunnen zich maandenlang dingen herinneren — de 3-seconden-mythe klopt niet."},"pl":{"statement":"Złote rybki mają pamięć trwającą tylko 3 sekundy.","isTrue":"false","explanation":"Złote rybki mogą pamiętać rzeczy przez wiele miesięcy — mit o 3 sekundach jest fałszywy."},"pt":{"statement":"Os peixes dourados têm memória de apenas 3 segundos.","isTrue":"false","explanation":"Os peixes dourados conseguem lembrar-se de coisas durante meses — o mito dos 3 segundos é falso."},"tr":{"statement":"Japon balıklarının hafızası sadece 3 saniyedir.","isTrue":"false","explanation":"Japon balıkları aylarca hatırlayabilir — 3 saniyelik hafıza efsanesi yanlıştır."},"ar":{"statement":"السمكة الذهبية لديها ذاكرة مدتها 3 ثوانٍ فقط.","isTrue":"false","explanation":"يمكن للسمكة الذهبية أن تتذكر الأشياء لأشهر — أسطورة الثلاث ثوانٍ خاطئة."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Honig kann niemals schlecht werden.","isTrue":"true","explanation":"In ägyptischen Graebern wurde 3000 Jahre alter Honig gefunden, der noch essbar war."},"en":{"statement":"Honey never goes bad.","isTrue":"true","explanation":"3,000-year-old honey found in Egyptian tombs was still perfectly edible."},"es":{"statement":"La miel nunca se echa a perder.","isTrue":"true","explanation":"En tumbas egipcias se encontró miel de 3000 años de antigüedad que aún era comestible."},"fr":{"statement":"Le miel ne se périme jamais.","isTrue":"true","explanation":"Du miel vieux de 3000 ans a été trouvé dans des tombeaux égyptiens et était encore comestible."},"it":{"statement":"Il miele non scade mai.","isTrue":"true","explanation":"In tombe egizie è stato trovato miele di 3000 anni ancora commestibile."},"nl":{"statement":"Honing kan nooit bederven.","isTrue":"true","explanation":"In Egyptische graven is 3000 jaar oude honing gevonden die nog eetbaar was."},"pl":{"statement":"Miód nigdy się nie psuje.","isTrue":"true","explanation":"W egipskich grobowcach znaleziono 3000-letni miód, który wciąż nadawał się do jedzenia."},"pt":{"statement":"O mel nunca se estraga.","isTrue":"true","explanation":"Em túmulos egípcios foi encontrado mel com 3000 anos que ainda era comestível."},"tr":{"statement":"Bal asla bozulmaz.","isTrue":"true","explanation":"Mısır mezarlarında bulunan 3000 yıllık balın hâlâ yenilebilir durumda olduğu tespit edilmiştir."},"ar":{"statement":"العسل لا يفسد أبداً.","isTrue":"true","explanation":"تم العثور على عسل عمره 3000 عام في مقابر مصرية وكان لا يزال صالحاً للأكل."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Krokodile können nicht mit der Zunge lecken.","isTrue":"true","explanation":"Die Zunge eines Krokodils ist am Gaumen festgewachsen und kann nicht herausgestreckt werden."},"en":{"statement":"Crocodiles cannot stick out their tongues.","isTrue":"true","explanation":"A crocodile''s tongue is attached to the roof of its mouth and cannot be extended."},"es":{"statement":"Los cocodrilos no pueden lamer con la lengua.","isTrue":"true","explanation":"La lengua de un cocodrilo está adherida al paladar y no puede sacarse."},"fr":{"statement":"Les crocodiles ne peuvent pas lécher avec leur langue.","isTrue":"true","explanation":"La langue d\\"},"it":{"statement":"I coccodrilli non possono leccare con la lingua.","isTrue":"true","explanation":"La lingua di un coccodrillo è attaccata al palato e non può essere sporta."},"nl":{"statement":"Krokodillen kunnen niet met hun tong likken.","isTrue":"true","explanation":"De tong van een krokodil zit vast aan het gehemelte en kan niet uitgestoken worden."},"pl":{"statement":"Krokodyle nie mogą lizać językiem.","isTrue":"true","explanation":"Język krokodyla jest przyrośnięty do podniebienia i nie może być wysunięty."},"pt":{"statement":"Os crocodilos não conseguem lamber com a língua.","isTrue":"true","explanation":"A língua do crocodilo está presa ao palato e não pode ser projetada para fora."},"tr":{"statement":"Timsahlar dilleriyle yalayamazlar.","isTrue":"true","explanation":"Timsahın dili damağına yapışıktır ve dışarı çıkarılamaz."},"ar":{"statement":"التماسيح لا تستطيع اللعق بلسانها.","isTrue":"true","explanation":"لسان التمساح ملتصق بسقف الفم ولا يمكن إخراجه."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Elefanten sind die einzigen Tiere, die nicht springen können.","isTrue":"true","explanation":"Aufgrund ihres Gewichts und ihrer Knochenstruktur können Elefanten tatsächlich nicht springen."},"en":{"statement":"Elephants are the only animals that cannot jump.","isTrue":"true","explanation":"Due to their weight and bone structure, elephants truly cannot jump."},"es":{"statement":"Los elefantes son los únicos animales que no pueden saltar.","isTrue":"true","explanation":"Debido a su peso y estructura ósea, los elefantes realmente no pueden saltar."},"fr":{"statement":"Les éléphants sont les seuls animaux qui ne peuvent pas sauter.","isTrue":"true","explanation":"En raison de leur poids et de leur structure osseuse, les éléphants ne peuvent effectivement pas sauter."},"it":{"statement":"Gli elefanti sono gli unici animali che non possono saltare.","isTrue":"true","explanation":"A causa del loro peso e della struttura ossea, gli elefanti effettivamente non possono saltare."},"nl":{"statement":"Olifanten zijn de enige dieren die niet kunnen springen.","isTrue":"true","explanation":"Door hun gewicht en botstructuur kunnen olifanten daadwerkelijk niet springen."},"pl":{"statement":"Słonie są jedynymi zwierzętami, które nie potrafią skakać.","isTrue":"true","explanation":"Ze względu na swoją wagę i budowę kości słonie faktycznie nie mogą skakać."},"pt":{"statement":"Os elefantes são os únicos animais que não conseguem saltar.","isTrue":"true","explanation":"Devido ao seu peso e estrutura óssea, os elefantes realmente não conseguem saltar."},"tr":{"statement":"Filler zıplayamayan tek hayvanlardır.","isTrue":"true","explanation":"Ağırlıkları ve kemik yapıları nedeniyle filler gerçekten zıplayamazlar."},"ar":{"statement":"الفيلة هي الحيوانات الوحيدة التي لا تستطيع القفز.","isTrue":"true","explanation":"بسبب وزنها وتركيب عظامها، لا تستطيع الفيلة فعلاً القفز."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Bananen wachsen auf Bäumen.","isTrue":"false","explanation":"Bananenpflanzen sind keine Baeume, sondern riesige Staudenpflanzen."},"en":{"statement":"Bananas grow on trees.","isTrue":"false","explanation":"Banana plants are not trees — they are giant herbaceous plants."},"es":{"statement":"Los plátanos crecen en árboles.","isTrue":"false","explanation":"Las plantas de plátano no son árboles, sino plantas herbáceas gigantes."},"fr":{"statement":"Les bananes poussent sur des arbres.","isTrue":"false","explanation":"Les bananiers ne sont pas des arbres, mais des plantes herbacées géantes."},"it":{"statement":"Le banane crescono sugli alberi.","isTrue":"false","explanation":"Le piante di banano non sono alberi, ma piante erbacee giganti."},"nl":{"statement":"Bananen groeien aan bomen.","isTrue":"false","explanation":"Bananenplanten zijn geen bomen, maar reusachtige kruidachtige planten."},"pl":{"statement":"Banany rosną na drzewach.","isTrue":"false","explanation":"Bananowce nie są drzewami, lecz gigantycznymi roślinami zielnymi."},"pt":{"statement":"As bananas crescem em árvores.","isTrue":"false","explanation":"As bananeiras não são árvores, mas sim plantas herbáceas gigantes."},"tr":{"statement":"Muzlar ağaçlarda yetişir.","isTrue":"false","explanation":"Muz bitkileri ağaç değil, dev otsu bitkilerdir."},"ar":{"statement":"الموز ينمو على الأشجار.","isTrue":"false","explanation":"نباتات الموز ليست أشجاراً بل هي نباتات عشبية عملاقة."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Ein Blitz kann die gleiche Stelle zweimal treffen.","isTrue":"true","explanation":"Hohe Gebäude wie das Empire State Building werden jedes Jahr bis zu 100 Mal getroffen."},"en":{"statement":"Lightning can strike the same place twice.","isTrue":"true","explanation":"Tall buildings like the Empire State Building get struck up to 100 times per year."},"es":{"statement":"Un rayo puede caer dos veces en el mismo lugar.","isTrue":"true","explanation":"Edificios altos como el Empire State Building son alcanzados hasta 100 veces al año."},"fr":{"statement":"La foudre peut frapper deux fois au même endroit.","isTrue":"true","explanation":"Les bâtiments élevés comme l\\"},"it":{"statement":"Un fulmine può colpire due volte nello stesso punto.","isTrue":"true","explanation":"Edifici alti come l\\"},"nl":{"statement":"Bliksem kan dezelfde plek twee keer raken.","isTrue":"true","explanation":"Hoge gebouwen zoals het Empire State Building worden elk jaar tot 100 keer getroffen."},"pl":{"statement":"Piorun może uderzyć dwa razy w to samo miejsce.","isTrue":"true","explanation":"Wysokie budynki, takie jak Empire State Building, są uderzane piorunami nawet 100 razy rocznie."},"pt":{"statement":"Um raio pode atingir o mesmo lugar duas vezes.","isTrue":"true","explanation":"Edifícios altos como o Empire State Building são atingidos até 100 vezes por ano."},"tr":{"statement":"Yıldırım aynı yere iki kez düşebilir.","isTrue":"true","explanation":"Empire State Building gibi yüksek binalar yılda 100 keze kadar yıldırım çarpmasına maruz kalır."},"ar":{"statement":"يمكن للبرق أن يضرب نفس المكان مرتين.","isTrue":"true","explanation":"المباني العالية مثل مبنى إمباير ستيت تتعرض للصواعق حتى 100 مرة سنوياً."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Delfine schlafen mit einem offenen Auge.","isTrue":"true","explanation":"Delfine schlafen mit einer Gehirnhälfte und halten ein Auge offen fürRaubtiere."},"en":{"statement":"Dolphins sleep with one eye open.","isTrue":"true","explanation":"Dolphins sleep with one half of their brain at a time, keeping one eye open to watch for predators."},"es":{"statement":"Los delfines duermen con un ojo abierto.","isTrue":"true","explanation":"Los delfines duermen con una mitad del cerebro y mantienen un ojo abierto para detectar depredadores."},"fr":{"statement":"Les dauphins dorment avec un œil ouvert.","isTrue":"true","explanation":"Les dauphins dorment avec une moitié du cerveau et gardent un œil ouvert pour les prédateurs."},"it":{"statement":"I delfini dormono con un occhio aperto.","isTrue":"true","explanation":"I delfini dormono con una metà del cervello e tengono un occhio aperto per i predatori."},"nl":{"statement":"Dolfijnen slapen met één oog open.","isTrue":"true","explanation":"Dolfijnen slapen met één hersenhelft en houden één oog open voor roofdieren."},"pl":{"statement":"Delfiny śpią z jednym otwartym okiem.","isTrue":"true","explanation":"Delfiny śpią jedną półkulą mózgu i trzymają jedno oko otwarte, by wypatrywać drapieżników."},"pt":{"statement":"Os golfinhos dormem com um olho aberto.","isTrue":"true","explanation":"Os golfinhos dormem com metade do cérebro e mantêm um olho aberto para vigiar predadores."},"tr":{"statement":"Yunuslar bir gözleri açık uyur.","isTrue":"true","explanation":"Yunuslar beynin bir yarısıyla uyur ve avcılara karşı bir gözlerini açık tutarlar."},"ar":{"statement":"الدلافين تنام بعين واحدة مفتوحة.","isTrue":"true","explanation":"تنام الدلافين بنصف دماغها وتبقي عيناً واحدة مفتوحة لمراقبة المفترسين."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Koalas trinken kein Wasser.","isTrue":"false","explanation":"Koalas trinken selten Wasser, da sie Feuchtigkeit aus Eukalyptusblättern beziehen, aber bei Hitze trinken sie durchaus."},"en":{"statement":"Koalas don''t drink water.","isTrue":"false","explanation":"Koalas rarely drink water since they get moisture from eucalyptus leaves, but they do drink during heat waves."},"es":{"statement":"Los koalas no beben agua.","isTrue":"false","explanation":"Los koalas rara vez beben agua ya que obtienen humedad de las hojas de eucalipto, pero sí beben cuando hace calor."},"fr":{"statement":"Les koalas ne boivent pas d\\","isTrue":"false","explanation":"Les koalas boivent rarement de l\\"},"it":{"statement":"I koala non bevono acqua.","isTrue":"false","explanation":"I koala bevono raramente acqua poiché ottengono umidità dalle foglie di eucalipto, ma quando fa caldo bevono eccome."},"nl":{"statement":"Koala\\","isTrue":"false","explanation":"Koala\\"},"pl":{"statement":"Koale nie piją wody.","isTrue":"false","explanation":"Koale rzadko piją wodę, ponieważ czerpią wilgoć z liści eukaliptusa, ale w upały jak najbardziej piją."},"pt":{"statement":"Os coalas não bebem água.","isTrue":"false","explanation":"Os coalas raramente bebem água, pois obtêm humidade das folhas de eucalipto, mas em dias quentes bebem sim."},"tr":{"statement":"Koalalar su içmez.","isTrue":"false","explanation":"Koalalar okaliptüs yapraklarından nem aldıkları için nadiren su içerler, ancak sıcak havalarda içerler."},"ar":{"statement":"الكوالا لا تشرب الماء.","isTrue":"false","explanation":"الكوالا نادراً ما تشرب الماء لأنها تحصل على الرطوبة من أوراق الكينا، لكنها تشرب في الأيام الحارة."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Schmetterlinge schmecken mit ihren Füßen.","isTrue":"true","explanation":"Schmetterlinge haben Geschmacksrezeptoren an ihren Füßen, um Pflanzen zu identifizieren."},"en":{"statement":"Butterflies taste with their feet.","isTrue":"true","explanation":"Butterflies have taste receptors on their feet to identify plants."},"es":{"statement":"Las mariposas saborean con los pies.","isTrue":"true","explanation":"Las mariposas tienen receptores gustativos en los pies para identificar plantas."},"fr":{"statement":"Les papillons goûtent avec leurs pieds.","isTrue":"true","explanation":"Les papillons ont des récepteurs gustatifs sur les pieds pour identifier les plantes."},"it":{"statement":"Le farfalle assaporano con i piedi.","isTrue":"true","explanation":"Le farfalle hanno recettori gustativi sui piedi per identificare le piante."},"nl":{"statement":"Vlinders proeven met hun poten.","isTrue":"true","explanation":"Vlinders hebben smaakreceporen aan hun poten om planten te identificeren."},"pl":{"statement":"Motyle smakują stopami.","isTrue":"true","explanation":"Motyle mają receptory smakowe na stopach, które pozwalają im identyfikować rośliny."},"pt":{"statement":"As borboletas sentem o sabor com os pés.","isTrue":"true","explanation":"As borboletas têm recetores gustativos nos pés para identificar plantas."},"tr":{"statement":"Kelebekler ayaklarıyla tat alır.","isTrue":"true","explanation":"Kelebeklerin ayaklarında bitkileri tanımlayan tat reseptörleri bulunur."},"ar":{"statement":"الفراشات تتذوق بأقدامها.","isTrue":"true","explanation":"لدى الفراشات مستقبلات تذوق في أقدامها لتحديد النباتات."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Schall reist schneller als Licht.","isTrue":"false","explanation":"Licht reist mit etwa 300.000 km/s, Schall nur mit etwa 343 m/s."},"en":{"statement":"Sound travels faster than light.","isTrue":"false","explanation":"Light travels at about 300,000 km/s, while sound only travels at about 343 m/s."},"es":{"statement":"El sonido viaja más rápido que la luz.","isTrue":"false","explanation":"La luz viaja a unos 300.000 km/s, el sonido solo a unos 343 m/s."},"fr":{"statement":"Le son voyage plus vite que la lumière.","isTrue":"false","explanation":"La lumière voyage à environ 300 000 km/s, le son à seulement environ 343 m/s."},"it":{"statement":"Il suono viaggia più veloce della luce.","isTrue":"false","explanation":"La luce viaggia a circa 300.000 km/s, il suono solo a circa 343 m/s."},"nl":{"statement":"Geluid reist sneller dan licht.","isTrue":"false","explanation":"Licht reist met ongeveer 300.000 km/s, geluid slechts met ongeveer 343 m/s."},"pl":{"statement":"Dźwięk podróżuje szybciej niż światło.","isTrue":"false","explanation":"Światło podróżuje z prędkością ok. 300 000 km/s, dźwięk jedynie ok. 343 m/s."},"pt":{"statement":"O som viaja mais rápido do que a luz.","isTrue":"false","explanation":"A luz viaja a cerca de 300.000 km/s, o som apenas a cerca de 343 m/s."},"tr":{"statement":"Ses ışıktan daha hızlı yol alır.","isTrue":"false","explanation":"Işık yaklaşık 300.000 km/s hızla, ses ise yalnızca yaklaşık 343 m/s hızla yol alır."},"ar":{"statement":"الصوت ينتقل أسرع من الضوء.","isTrue":"false","explanation":"ينتقل الضوء بسرعة حوالي 300,000 كم/ث، بينما الصوت بحوالي 343 م/ث فقط."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Mensch besteht zu etwa 60% aus Wasser.","isTrue":"true","explanation":"Der menschliche Körper besteht je nach Alter zu 50-75% aus Wasser."},"en":{"statement":"The human body is about 60% water.","isTrue":"true","explanation":"Depending on age, the human body is 50-75% water."},"es":{"statement":"El cuerpo humano está compuesto por aproximadamente un 60% de agua.","isTrue":"true","explanation":"El cuerpo humano está compuesto entre un 50-75% de agua según la edad."},"fr":{"statement":"Le corps humain est composé d\\","isTrue":"true","explanation":"Le corps humain est composé de 50 à 75% d\\"},"it":{"statement":"Il corpo umano è composto per circa il 60% da acqua.","isTrue":"true","explanation":"Il corpo umano è composto dal 50 al 75% di acqua a seconda dell\\"},"nl":{"statement":"Het menselijk lichaam bestaat voor ongeveer 60% uit water.","isTrue":"true","explanation":"Het menselijk lichaam bestaat, afhankelijk van leeftijd, voor 50-75% uit water."},"pl":{"statement":"Ciało człowieka składa się w około 60% z wody.","isTrue":"true","explanation":"Ciało ludzkie w zależności od wieku składa się w 50-75% z wody."},"pt":{"statement":"O corpo humano é composto por cerca de 60% de água.","isTrue":"true","explanation":"O corpo humano é composto por 50-75% de água, dependendo da idade."},"tr":{"statement":"İnsan vücudunun yaklaşık %60\\","isTrue":"true","explanation":"İnsan vücudu yaşa bağlı olarak %50-75 oranında sudan oluşur."},"ar":{"statement":"يتكون جسم الإنسان من حوالي 60% من الماء.","isTrue":"true","explanation":"يتكون جسم الإنسان من 50-75% من الماء حسب العمر."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Venus dreht sich in die entgegengesetzte Richtung der meisten Planeten.","isTrue":"true","explanation":"Venus hat eine retrograde Rotation — die Sonne geht dort im Westen auf."},"en":{"statement":"Venus spins in the opposite direction of most planets.","isTrue":"true","explanation":"Venus has a retrograde rotation — the sun rises in the west there."},"es":{"statement":"Venus gira en dirección opuesta a la mayoría de los planetas.","isTrue":"true","explanation":"Venus tiene una rotación retrógrada — el sol sale por el oeste allí."},"fr":{"statement":"Vénus tourne dans le sens opposé à la plupart des planètes.","isTrue":"true","explanation":"Vénus a une rotation rétrograde — le soleil s\\"},"it":{"statement":"Venere ruota nella direzione opposta rispetto alla maggior parte dei pianeti.","isTrue":"true","explanation":"Venere ha una rotazione retrograda — il sole lì sorge a ovest."},"nl":{"statement":"Venus draait in de tegenovergestelde richting van de meeste planeten.","isTrue":"true","explanation":"Venus heeft een retrograde rotatie — de zon komt daar in het westen op."},"pl":{"statement":"Wenus obraca się w przeciwnym kierunku niż większość planet.","isTrue":"true","explanation":"Wenus ma rotację wsteczną — słońce tam wschodzi na zachodzie."},"pt":{"statement":"Vénus gira na direção oposta à da maioria dos planetas.","isTrue":"true","explanation":"Vénus tem uma rotação retrógrada — o sol nasce no oeste lá."},"tr":{"statement":"Venüs, çoğu gezegenin tersi yönünde döner.","isTrue":"true","explanation":"Venüs\\"},"ar":{"statement":"كوكب الزهرة يدور في الاتجاه المعاكس لمعظم الكواكب.","isTrue":"true","explanation":"كوكب الزهرة له دوران رجعي — تشرق الشمس هناك من الغرب."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Glas ist eine Flüssigkeit.","isTrue":"false","explanation":"Glas ist ein amorpher Feststoff. Der Mythos von fließendem Glas in alten Fenstern ist falsch."},"en":{"statement":"Glass is a liquid.","isTrue":"false","explanation":"Glass is an amorphous solid. The myth about old window glass flowing is false."},"es":{"statement":"El vidrio es un líquido.","isTrue":"false","explanation":"El vidrio es un sólido amorfo. El mito del vidrio que fluye en ventanas antiguas es falso."},"fr":{"statement":"Le verre est un liquide.","isTrue":"false","explanation":"Le verre est un solide amorphe. Le mythe du verre qui coule dans les vieilles fenêtres est faux."},"it":{"statement":"Il vetro è un liquido.","isTrue":"false","explanation":"Il vetro è un solido amorfo. Il mito del vetro che scorre nelle vecchie finestre è falso."},"nl":{"statement":"Glas is een vloeistof.","isTrue":"false","explanation":"Glas is een amorf vast materiaal. De mythe van vloeiend glas in oude ramen klopt niet."},"pl":{"statement":"Szkło jest cieczą.","isTrue":"false","explanation":"Szkło jest amorficznym ciałem stałym. Mit o płynącym szkle w starych oknach jest fałszywy."},"pt":{"statement":"O vidro é um líquido.","isTrue":"false","explanation":"O vidro é um sólido amorfo. O mito de vidro a fluir em janelas antigas é falso."},"tr":{"statement":"Cam bir sıvıdır.","isTrue":"false","explanation":"Cam amorf bir katıdır. Eski pencerelerde camın aktığı efsanesi yanlıştır."},"ar":{"statement":"الزجاج سائل.","isTrue":"false","explanation":"الزجاج مادة صلبة غير متبلورة. أسطورة انسياب الزجاج في النوافذ القديمة خاطئة."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Ein Tag auf der Venus ist länger als ein Jahr auf der Venus.","isTrue":"true","explanation":"Eine Rotation dauert 243 Erdtage, eine Umrundung der Sonne nur 225 Erdtage."},"en":{"statement":"A day on Venus is longer than a year on Venus.","isTrue":"true","explanation":"One rotation takes 243 Earth days, while one orbit around the Sun takes only 225 Earth days."},"es":{"statement":"Un día en Venus es más largo que un año en Venus.","isTrue":"true","explanation":"Una rotación dura 243 días terrestres, una órbita alrededor del sol solo 225 días terrestres."},"fr":{"statement":"Un jour sur Vénus est plus long qu\\","isTrue":"true","explanation":"Une rotation dure 243 jours terrestres, une orbite autour du soleil seulement 225 jours terrestres."},"it":{"statement":"Un giorno su Venere è più lungo di un anno su Venere.","isTrue":"true","explanation":"Una rotazione dura 243 giorni terrestri, un\\"},"nl":{"statement":"Een dag op Venus is langer dan een jaar op Venus.","isTrue":"true","explanation":"Eén rotatie duurt 243 aardse dagen, één omwenteling om de zon slechts 225 aardse dagen."},"pl":{"statement":"Dzień na Wenus trwa dłużej niż rok na Wenus.","isTrue":"true","explanation":"Jeden obrót trwa 243 dni ziemskie, a okrążenie Słońca tylko 225 dni ziemskich."},"pt":{"statement":"Um dia em Vénus é mais longo do que um ano em Vénus.","isTrue":"true","explanation":"Uma rotação demora 243 dias terrestres, uma órbita em torno do Sol apenas 225 dias terrestres."},"tr":{"statement":"Venüs\\","isTrue":"true","explanation":"Bir dönüş 243 Dünya günü sürerken, Güneş\\"},"ar":{"statement":"اليوم على كوكب الزهرة أطول من السنة على كوكب الزهرة.","isTrue":"true","explanation":"دورة واحدة حول محوره تستغرق 243 يوماً أرضياً، بينما دورته حول الشمس تستغرق 225 يوماً فقط."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Menschen nutzen nur 10% ihres Gehirns.","isTrue":"false","explanation":"Hirnscans zeigen, dass wir praktisch alle Bereiche des Gehirns nutzen, nur nicht alle gleichzeitig."},"en":{"statement":"Humans only use 10% of their brain.","isTrue":"false","explanation":"Brain scans show that we use virtually all areas of the brain, just not all at the same time."},"es":{"statement":"Los humanos solo usan el 10% de su cerebro.","isTrue":"false","explanation":"Las imágenes cerebrales muestran que usamos prácticamente todas las áreas del cerebro, solo que no todas al mismo tiempo."},"fr":{"statement":"Les humains n\\","isTrue":"false","explanation":"Les scanners cérébraux montrent que nous utilisons pratiquement toutes les zones du cerveau, mais pas toutes en même temps."},"it":{"statement":"Gli esseri umani usano solo il 10% del cervello.","isTrue":"false","explanation":"Le scansioni cerebrali mostrano che usiamo praticamente tutte le aree del cervello, solo non tutte contemporaneamente."},"nl":{"statement":"Mensen gebruiken slechts 10% van hun hersenen.","isTrue":"false","explanation":"Hersenscans tonen aan dat we vrijwel alle delen van de hersenen gebruiken, alleen niet allemaal tegelijk."},"pl":{"statement":"Ludzie wykorzystują tylko 10% swojego mózgu.","isTrue":"false","explanation":"Skany mózgu pokazują, że wykorzystujemy praktycznie wszystkie jego obszary, tylko nie wszystkie jednocześnie."},"pt":{"statement":"Os humanos usam apenas 10% do cérebro.","isTrue":"false","explanation":"Exames cerebrais mostram que usamos praticamente todas as áreas do cérebro, apenas não todas ao mesmo tempo."},"tr":{"statement":"İnsanlar beyninin yalnızca %10\\","isTrue":"false","explanation":"Beyin taramaları, beynin neredeyse tüm bölgelerini kullandığımızı gösterir, sadece hepsini aynı anda değil."},"ar":{"statement":"يستخدم البشر 10% فقط من أدمغتهم.","isTrue":"false","explanation":"تُظهر فحوصات الدماغ أننا نستخدم جميع مناطق الدماغ تقريباً، لكن ليس جميعها في وقت واحد."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Diamanten entstehen aus Kohle.","isTrue":"false","explanation":"Diamanten entstehen aus Kohlenstoff unter extremem Druck, aber nicht aus Kohle — die meisten sind älter als Pflanzen auf der Erde."},"en":{"statement":"Diamonds are made from coal.","isTrue":"false","explanation":"Diamonds form from carbon under extreme pressure, but not from coal — most are older than plant life on Earth."},"es":{"statement":"Los diamantes se forman a partir del carbón.","isTrue":"false","explanation":"Los diamantes se forman del carbono bajo presión extrema, pero no del carbón — la mayoría son más antiguos que las plantas en la Tierra."},"fr":{"statement":"Les diamants se forment à partir du charbon.","isTrue":"false","explanation":"Les diamants se forment à partir de carbone sous pression extrême, mais pas du charbon — la plupart sont plus anciens que les plantes sur Terre."},"it":{"statement":"I diamanti si formano dal carbone.","isTrue":"false","explanation":"I diamanti si formano dal carbonio sotto pressione estrema, ma non dal carbone — la maggior parte è più antica delle piante sulla Terra."},"nl":{"statement":"Diamanten ontstaan uit steenkool.","isTrue":"false","explanation":"Diamanten ontstaan uit koolstof onder extreme druk, maar niet uit steenkool — de meeste zijn ouder dan planten op aarde."},"pl":{"statement":"Diamenty powstają z węgla.","isTrue":"false","explanation":"Diamenty powstają z węgla pierwiastkowego pod ekstremalnym ciśnieniem, ale nie z węgla kamiennego — większość z nich jest starsza niż rośliny na Ziemi."},"pt":{"statement":"Os diamantes formam-se a partir de carvão.","isTrue":"false","explanation":"Os diamantes formam-se a partir de carbono sob pressão extrema, mas não de carvão — a maioria é mais antiga do que as plantas na Terra."},"tr":{"statement":"Elmaslar kömürden oluşur.","isTrue":"false","explanation":"Elmaslar aşırı basınç altında karbondan oluşur, ancak kömürden değil — çoğu, Dünya\\"},"ar":{"statement":"الألماس يتكون من الفحم.","isTrue":"false","explanation":"الألماس يتكون من الكربون تحت ضغط هائل، لكن ليس من الفحم — معظمه أقدم من النباتات على الأرض."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Im Weltraum herrscht absolute Stille.","isTrue":"true","explanation":"Schall braucht ein Medium zur Ausbreitung. Im Vakuum des Weltalls gibt es keines."},"en":{"statement":"There is absolute silence in space.","isTrue":"true","explanation":"Sound needs a medium to travel through. In the vacuum of space, there is none."},"es":{"statement":"En el espacio hay silencio absoluto.","isTrue":"true","explanation":"El sonido necesita un medio para propagarse. En el vacío del espacio no hay ninguno."},"fr":{"statement":"Dans l\\","isTrue":"true","explanation":"Le son a besoin d\\"},"it":{"statement":"Nello spazio c\\","isTrue":"true","explanation":"Il suono ha bisogno di un mezzo per propagarsi. Nel vuoto dello spazio non ce n\\"},"nl":{"statement":"In de ruimte heerst absolute stilte.","isTrue":"true","explanation":"Geluid heeft een medium nodig om zich voort te planten. In het vacuüm van de ruimte is dat er niet."},"pl":{"statement":"W kosmosie panuje absolutna cisza.","isTrue":"true","explanation":"Dźwięk potrzebuje medium do rozchodzenia się. W próżni kosmosu takiego medium nie ma."},"pt":{"statement":"No espaço reina o silêncio absoluto.","isTrue":"true","explanation":"O som precisa de um meio para se propagar. No vácuo do espaço, esse meio não existe."},"tr":{"statement":"Uzayda mutlak sessizlik hüküm sürer.","isTrue":"true","explanation":"Ses yayılmak için bir ortama ihtiyaç duyar. Uzayın boşluğunda böyle bir ortam yoktur."},"ar":{"statement":"في الفضاء يسود صمت مطلق.","isTrue":"true","explanation":"يحتاج الصوت إلى وسط للانتقال. في فراغ الفضاء لا يوجد مثل هذا الوسط."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der menschliche Körper hat mehr Bakterien als eigene Zellen.","isTrue":"true","explanation":"Schätzungen zufolge hat der Körper etwa 38 Billionen Bakterien bei 30 Billionen eigenen Zellen."},"en":{"statement":"The human body has more bacteria than its own cells.","isTrue":"true","explanation":"Estimates suggest the body has about 38 trillion bacteria compared to 30 trillion of its own cells."},"es":{"statement":"El cuerpo humano tiene más bacterias que células propias.","isTrue":"true","explanation":"Se estima que el cuerpo tiene unos 38 billones de bacterias frente a 30 billones de células propias."},"fr":{"statement":"Le corps humain a plus de bactéries que de cellules propres.","isTrue":"true","explanation":"On estime que le corps contient environ 38 billions de bactéries pour 30 billions de cellules propres."},"it":{"statement":"Il corpo umano ha più batteri che cellule proprie.","isTrue":"true","explanation":"Si stima che il corpo abbia circa 38 bilioni di batteri a fronte di 30 bilioni di cellule proprie."},"nl":{"statement":"Het menselijk lichaam heeft meer bacteriën dan eigen cellen.","isTrue":"true","explanation":"Schattingen geven aan dat het lichaam ongeveer 38 biljoen bacteriën heeft bij 30 biljoen eigen cellen."},"pl":{"statement":"Ludzkie ciało ma więcej bakterii niż własnych komórek.","isTrue":"true","explanation":"Szacunkowo organizm posiada ok. 38 bilionów bakterii przy 30 bilionach własnych komórek."},"pt":{"statement":"O corpo humano tem mais bactérias do que células próprias.","isTrue":"true","explanation":"Estima-se que o corpo tenha cerca de 38 biliões de bactérias e 30 biliões de células próprias."},"tr":{"statement":"İnsan vücudunda kendi hücrelerinden daha fazla bakteri bulunur.","isTrue":"true","explanation":"Tahminlere göre vücutta yaklaşık 38 trilyon bakteri ve 30 trilyon kendi hücresi vardır."},"ar":{"statement":"جسم الإنسان يحتوي على بكتيريا أكثر من خلاياه الخاصة.","isTrue":"true","explanation":"تشير التقديرات إلى أن الجسم يحتوي على حوالي 38 تريليون بكتيريا مقابل 30 تريليون خلية خاصة."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Wasser leitet Strom.","isTrue":"false","explanation":"Reines Wasser leitet keinen Strom. Erst die darin gelösten Mineralien und Salze machen es leitfähig."},"en":{"statement":"Water conducts electricity.","isTrue":"false","explanation":"Pure water does not conduct electricity. Only the dissolved minerals and salts make it conductive."},"es":{"statement":"El agua conduce la electricidad.","isTrue":"false","explanation":"El agua pura no conduce electricidad. Solo los minerales y sales disueltos en ella la hacen conductora."},"fr":{"statement":"L\\","isTrue":"false","explanation":"L\\"},"it":{"statement":"L\\","isTrue":"false","explanation":"L\\"},"nl":{"statement":"Water geleidt elektriciteit.","isTrue":"false","explanation":"Zuiver water geleidt geen elektriciteit. Pas de opgeloste mineralen en zouten maken het geleidend."},"pl":{"statement":"Woda przewodzi prąd.","isTrue":"false","explanation":"Czysta woda nie przewodzi prądu. Dopiero rozpuszczone w niej minerały i sole czynią ją przewodzącą."},"pt":{"statement":"A água conduz eletricidade.","isTrue":"false","explanation":"A água pura não conduz eletricidade. São os minerais e sais dissolvidos que a tornam condutora."},"tr":{"statement":"Su elektrik iletir.","isTrue":"false","explanation":"Saf su elektrik iletmez. Suda çözünmüş mineraller ve tuzlar onu iletken yapar."},"ar":{"statement":"الماء يوصل الكهرباء.","isTrue":"false","explanation":"الماء النقي لا يوصل الكهرباء. المعادن والأملاح المذابة فيه هي التي تجعله موصلاً."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Kleopatra lebte näher an der Mondlandung als am Bau der Pyramiden.","isTrue":"true","explanation":"Die Pyramiden wurden ca. 2560 v.Chr. gebaut, Kleopatra lebte 69-30 v.Chr., die Mondlandung war 1969."},"en":{"statement":"Cleopatra lived closer to the Moon landing than to the building of the pyramids.","isTrue":"true","explanation":"The pyramids were built around 2560 BC, Cleopatra lived 69-30 BC, and the Moon landing was in 1969."},"es":{"statement":"Cleopatra vivió más cerca del alunizaje que de la construcción de las pirámides.","isTrue":"true","explanation":"Las pirámides se construyeron alrededor del 2560 a.C., Cleopatra vivió del 69 al 30 a.C., el alunizaje fue en 1969."},"fr":{"statement":"Cléopâtre a vécu plus près de l\\","isTrue":"true","explanation":"Les pyramides ont été construites vers 2560 av. J.-C., Cléopâtre a vécu de 69 à 30 av. J.-C., l\\"},"it":{"statement":"Cleopatra è vissuta più vicina allo sbarco sulla Luna che alla costruzione delle piramidi.","isTrue":"true","explanation":"Le piramidi furono costruite intorno al 2560 a.C., Cleopatra visse dal 69 al 30 a.C., lo sbarco sulla Luna avvenne nel 1969."},"nl":{"statement":"Cleopatra leefde dichter bij de maanlanding dan bij de bouw van de piramides.","isTrue":"true","explanation":"De piramides werden rond 2560 v.Chr. gebouwd, Cleopatra leefde van 69-30 v.Chr., de maanlanding was in 1969."},"pl":{"statement":"Kleopatra żyła bliżej lądowania na Księżycu niż budowy piramid.","isTrue":"true","explanation":"Piramidy zbudowano ok. 2560 r. p.n.e., Kleopatra żyła w latach 69-30 p.n.e., lądowanie na Księżycu miało miejsce w 1969 r."},"pt":{"statement":"Cleópatra viveu mais perto da chegada à Lua do que da construção das pirâmides.","isTrue":"true","explanation":"As pirâmides foram construídas por volta de 2560 a.C., Cleópatra viveu de 69-30 a.C., a chegada à Lua foi em 1969."},"tr":{"statement":"Kleopatra, piramitlerin inşasından çok Ay\\","isTrue":"true","explanation":"Piramitler yaklaşık MÖ 2560\\"},"ar":{"statement":"عاشت كليوباترا أقرب زمنياً للهبوط على القمر من بناء الأهرامات.","isTrue":"true","explanation":"بُنيت الأهرامات حوالي 2560 ق.م، عاشت كليوباترا 69-30 ق.م، والهبوط على القمر كان عام 1969."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Napoleon war ungewöhnlich klein.","isTrue":"false","explanation":"Napoleon war ca. 1,70m groß — durchschnittlich fürseine Zeit. Der Mythos entstand durch britische Propaganda."},"en":{"statement":"Napoleon was unusually short.","isTrue":"false","explanation":"Napoleon was about 5\\"},"es":{"statement":"Napoleón era inusualmente bajo.","isTrue":"false","explanation":"Napoleón medía aprox. 1,70 m — normal para su época. El mito surgió de la propaganda británica."},"fr":{"statement":"Napoléon était exceptionnellement petit.","isTrue":"false","explanation":"Napoléon mesurait environ 1,70 m — une taille moyenne pour son époque. Le mythe provient de la propagande britannique."},"it":{"statement":"Napoleone era insolitamente basso.","isTrue":"false","explanation":"Napoleone era alto circa 1,70 m — nella media per la sua epoca. Il mito nacque dalla propaganda britannica."},"nl":{"statement":"Napoleon was ongewoon klein.","isTrue":"false","explanation":"Napoleon was ca. 1,70m lang — gemiddeld voor zijn tijd. De mythe ontstond door Britse propaganda."},"pl":{"statement":"Napoleon był niezwykle niski.","isTrue":"false","explanation":"Napoleon miał ok. 1,70 m wzrostu — średnio jak na swoje czasy. Mit powstał z brytyjskiej propagandy."},"pt":{"statement":"Napoleão era invulgarmente baixo.","isTrue":"false","explanation":"Napoleão tinha cerca de 1,70 m — a média para a sua época. O mito surgiu da propaganda britânica."},"tr":{"statement":"Napolyon alışılmadık derecede kısaydı.","isTrue":"false","explanation":"Napolyon yaklaşık 1,70 m boyundaydı — dönemine göre ortalama. Efsane İngiliz propagandasından kaynaklanır."},"ar":{"statement":"كان نابليون قصيراً بشكل غير عادي.","isTrue":"false","explanation":"كان نابليون بطول 1.70 م تقريباً — وهو متوسط بالنسبة لعصره. الأسطورة نشأت من الدعاية البريطانية."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Die Chinesische Mauer ist vom Mond aus sichtbar.","isTrue":"false","explanation":"Astronauten bestätigen, dass die Mauer vom Mond aus nicht sichtbar ist — sie ist zu schmal."},"en":{"statement":"The Great Wall of China is visible from the Moon.","isTrue":"false","explanation":"Astronauts confirm the Wall is not visible from the Moon — it is too narrow."},"es":{"statement":"La Gran Muralla China es visible desde la Luna.","isTrue":"false","explanation":"Los astronautas confirman que la muralla no es visible desde la Luna — es demasiado estrecha."},"fr":{"statement":"La Grande Muraille de Chine est visible depuis la Lune.","isTrue":"false","explanation":"Les astronautes confirment que la muraille n\\"},"it":{"statement":"La Grande Muraglia cinese è visibile dalla Luna.","isTrue":"false","explanation":"Gli astronauti confermano che la muraglia non è visibile dalla Luna — è troppo stretta."},"nl":{"statement":"De Chinese Muur is zichtbaar vanaf de maan.","isTrue":"false","explanation":"Astronauten bevestigen dat de muur niet zichtbaar is vanaf de maan — hij is te smal."},"pl":{"statement":"Wielki Mur Chiński jest widoczny z Księżyca.","isTrue":"false","explanation":"Astronauci potwierdzają, że mur nie jest widoczny z Księżyca — jest zbyt wąski."},"pt":{"statement":"A Muralha da China é visível da Lua.","isTrue":"false","explanation":"Astronautas confirmam que a muralha não é visível da Lua — é demasiado estreita."},"tr":{"statement":"Çin Seddi Ay\\","isTrue":"false","explanation":"Astronotlar, seddin Ay\\"},"ar":{"statement":"سور الصين العظيم مرئي من القمر.","isTrue":"false","explanation":"أكد رواد الفضاء أن السور غير مرئي من القمر — فهو ضيق جداً."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Oxford University ist älter als das Aztekenreich.","isTrue":"true","explanation":"Oxford wurde ab 1096 gegründet, das Aztekenreich erst 1428."},"en":{"statement":"Oxford University is older than the Aztec Empire.","isTrue":"true","explanation":"Oxford was founded around 1096, while the Aztec Empire was established in 1428."},"es":{"statement":"La Universidad de Oxford es más antigua que el Imperio Azteca.","isTrue":"true","explanation":"Oxford se fundó a partir de 1096, el Imperio Azteca recién en 1428."},"fr":{"statement":"L\\","isTrue":"true","explanation":"Oxford a été fondée à partir de 1096, l\\"},"it":{"statement":"L\\","isTrue":"true","explanation":"Oxford fu fondata a partire dal 1096, l\\"},"nl":{"statement":"De Universiteit van Oxford is ouder dan het Aztekenrijk.","isTrue":"true","explanation":"Oxford werd vanaf 1096 gesticht, het Aztekenrijk pas in 1428."},"pl":{"statement":"Uniwersytet Oksfordzki jest starszy niż imperium Azteków.","isTrue":"true","explanation":"Oxford został założony w 1096 r., imperium Azteków dopiero w 1428 r."},"pt":{"statement":"A Universidade de Oxford é mais antiga do que o Império Asteca.","isTrue":"true","explanation":"Oxford foi fundada a partir de 1096, o Império Asteca apenas em 1428."},"tr":{"statement":"Oxford Üniversitesi Aztek İmparatorluğu\\","isTrue":"true","explanation":"Oxford 1096\\"},"ar":{"statement":"جامعة أكسفورد أقدم من إمبراطورية الأزتك.","isTrue":"true","explanation":"تأسست أكسفورد ابتداءً من عام 1096، بينما إمبراطورية الأزتك لم تُؤسس إلا عام 1428."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Wikinger trugen Helme mit Hörnern.","isTrue":"false","explanation":"Archäologische Funde zeigen einfache Helme ohne Hoerner. Das Klischee stammt aus dem 19. Jahrhundert."},"en":{"statement":"Vikings wore helmets with horns.","isTrue":"false","explanation":"Archaeological finds show simple helmets without horns. The cliche comes from the 19th century."},"es":{"statement":"Los vikingos llevaban cascos con cuernos.","isTrue":"false","explanation":"Los hallazgos arqueológicos muestran cascos sencillos sin cuernos. El cliché proviene del siglo XIX."},"fr":{"statement":"Les Vikings portaient des casques à cornes.","isTrue":"false","explanation":"Les découvertes archéologiques montrent des casques simples sans cornes. Le cliché date du XIXe siècle."},"it":{"statement":"I vichinghi indossavano elmi con le corna.","isTrue":"false","explanation":"I ritrovamenti archeologici mostrano elmi semplici senza corna. Il cliché risale al XIX secolo."},"nl":{"statement":"Vikingen droegen helmen met hoorns.","isTrue":"false","explanation":"Archeologische vondsten tonen eenvoudige helmen zonder hoorns. Het cliché stamt uit de 19e eeuw."},"pl":{"statement":"Wikingowie nosili hełmy z rogami.","isTrue":"false","explanation":"Wykopaliska archeologiczne ukazują proste hełmy bez rogów. Stereotyp pochodzi z XIX wieku."},"pt":{"statement":"Os vikings usavam capacetes com chifres.","isTrue":"false","explanation":"Achados arqueológicos mostram capacetes simples sem chifres. O estereótipo vem do século XIX."},"tr":{"statement":"Vikingler boynuzlu miğfer takardı.","isTrue":"false","explanation":"Arkeolojik buluntular boynuzsuz basit miğferler göstermektedir. Klişe 19. yüzyıldan gelmektedir."},"ar":{"statement":"الفايكنغ كانوا يرتدون خوذاً بقرون.","isTrue":"false","explanation":"الاكتشافات الأثرية تُظهر خوذاً بسيطة بدون قرون. الصورة النمطية تعود للقرن التاسع عشر."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"In der Antike hielten die Menschen die Erde füreine Scheibe.","isTrue":"false","explanation":"Bereits die alten Griechen wussten, dass die Erde rund ist. Eratosthenes berechnete sogar ihren Umfang."},"en":{"statement":"In ancient times, people believed the Earth was flat.","isTrue":"false","explanation":"The ancient Greeks already knew the Earth was round. Eratosthenes even calculated its circumference."},"es":{"statement":"En la antigüedad la gente creía que la Tierra era plana.","isTrue":"false","explanation":"Ya los antiguos griegos sabían que la Tierra era redonda. Eratóstenes incluso calculó su circunferencia."},"fr":{"statement":"Dans l\\","isTrue":"false","explanation":"Les anciens Grecs savaient déjà que la Terre était ronde. Ératosthène a même calculé sa circonférence."},"it":{"statement":"Nell\\","isTrue":"false","explanation":"Già gli antichi greci sapevano che la Terra era rotonda. Eratostene ne calcolò persino la circonferenza."},"nl":{"statement":"In de oudheid dachten mensen dat de aarde plat was.","isTrue":"false","explanation":"Al de oude Grieken wisten dat de aarde rond is. Eratosthenes berekende zelfs haar omtrek."},"pl":{"statement":"W starożytności ludzie uważali, że Ziemia jest płaska.","isTrue":"false","explanation":"Już starożytni Grecy wiedzieli, że Ziemia jest okrągła. Eratostenes obliczył nawet jej obwód."},"pt":{"statement":"Na antiguidade, as pessoas achavam que a Terra era plana.","isTrue":"false","explanation":"Já os antigos gregos sabiam que a Terra é redonda. Eratóstenes até calculou a sua circunferência."},"tr":{"statement":"Antik çağda insanlar Dünya\\","isTrue":"false","explanation":"Eski Yunanlılar Dünya\\"},"ar":{"statement":"في العصور القديمة كان الناس يعتقدون أن الأرض مسطحة.","isTrue":"false","explanation":"عرف الإغريق القدماء أن الأرض كروية. بل إن إراتوستينس حسب محيطها."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Eiffelturm sollte nach 20 Jahren abgerissen werden.","isTrue":"true","explanation":"Er wurde 1889 als temporäres Bauwerk errichtet und überlebte nur, weil er als Funkturm nützlich war."},"en":{"statement":"The Eiffel Tower was supposed to be torn down after 20 years.","isTrue":"true","explanation":"It was built in 1889 as a temporary structure and only survived because it was useful as a radio tower."},"es":{"statement":"La Torre Eiffel iba a ser demolida después de 20 años.","isTrue":"true","explanation":"Fue construida en 1889 como estructura temporal y solo sobrevivió porque era útil como torre de radio."},"fr":{"statement":"La tour Eiffel devait être démolie après 20 ans.","isTrue":"true","explanation":"Elle a été construite en 1889 comme structure temporaire et n\\"},"it":{"statement":"La Torre Eiffel doveva essere demolita dopo 20 anni.","isTrue":"true","explanation":"Fu costruita nel 1889 come struttura temporanea e sopravvisse solo perché era utile come torre radio."},"nl":{"statement":"De Eiffeltoren zou na 20 jaar afgebroken worden.","isTrue":"true","explanation":"Hij werd in 1889 als tijdelijk bouwwerk opgericht en overleefde alleen omdat hij als zendmast nuttig was."},"pl":{"statement":"Wieża Eiffla miała zostać rozebrana po 20 latach.","isTrue":"true","explanation":"Została wzniesiona w 1889 r. jako budowla tymczasowa i przetrwała jedynie dlatego, że okazała się przydatna jako wieża radiowa."},"pt":{"statement":"A Torre Eiffel deveria ser demolida após 20 anos.","isTrue":"true","explanation":"Foi erguida em 1889 como estrutura temporária e sobreviveu apenas porque foi útil como torre de rádio."},"tr":{"statement":"Eyfel Kulesi 20 yıl sonra yıkılacaktı.","isTrue":"true","explanation":"1889\\"},"ar":{"statement":"كان من المفترض هدم برج إيفل بعد 20 عاماً.","isTrue":"true","explanation":"بُني عام 1889 كمنشأة مؤقتة ونجا فقط لأنه كان مفيداً كبرج إرسال لاسلكي."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Die Titanic wurde als unsinkbar beworben.","isTrue":"false","explanation":"Die White Star Line nannte sie nie offiziell unsinkbar. Das war eine Übertreibung der Presse."},"en":{"statement":"The Titanic was advertised as unsinkable.","isTrue":"false","explanation":"The White Star Line never officially called it unsinkable. That was a media exaggeration."},"es":{"statement":"El Titanic fue promocionado como insumergible.","isTrue":"false","explanation":"La White Star Line nunca lo llamó oficialmente insumergible. Fue una exageración de la prensa."},"fr":{"statement":"Le Titanic a été présenté comme insubmersible.","isTrue":"false","explanation":"La White Star Line ne l\\"},"it":{"statement":"Il Titanic fu pubblicizzato come inaffondabile.","isTrue":"false","explanation":"La White Star Line non lo definì mai ufficialmente inaffondabile. Fu un\\"},"nl":{"statement":"De Titanic werd als onzinkbaar aangeprezen.","isTrue":"false","explanation":"De White Star Line noemde haar nooit officieel onzinkbaar. Dat was een overdrijving van de pers."},"pl":{"statement":"Titanic był reklamowany jako niezatapialny.","isTrue":"false","explanation":"White Star Line nigdy oficjalnie nie nazwała go niezatapialnym. To była przesada prasy."},"pt":{"statement":"O Titanic foi promovido como inafundável.","isTrue":"false","explanation":"A White Star Line nunca o chamou oficialmente de inafundável. Foi um exagero da imprensa."},"tr":{"statement":"Titanic batmaz olarak tanıtılmıştı.","isTrue":"false","explanation":"White Star Line onu hiçbir zaman resmi olarak batmaz olarak adlandırmadı. Bu basının abartısıydı."},"ar":{"statement":"تم الترويج لسفينة تايتانيك على أنها غير قابلة للغرق.","isTrue":"false","explanation":"لم تصفها شركة وايت ستار لاين رسمياً بأنها غير قابلة للغرق. كانت مبالغة من الصحافة."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Albert Einstein ist in Mathe durchgefallen.","isTrue":"false","explanation":"Einstein hatte Bestnoten in Mathematik. Dieser Mythos ist völlig falsch."},"en":{"statement":"Albert Einstein failed math in school.","isTrue":"false","explanation":"Einstein had top grades in mathematics. This myth is completely false."},"es":{"statement":"Albert Einstein suspendió en matemáticas.","isTrue":"false","explanation":"Einstein tenía las mejores notas en matemáticas. Este mito es completamente falso."},"fr":{"statement":"Albert Einstein a échoué en mathématiques.","isTrue":"false","explanation":"Einstein avait d\\"},"it":{"statement":"Albert Einstein fu bocciato in matematica.","isTrue":"false","explanation":"Einstein aveva i voti più alti in matematica. Questo mito è completamente falso."},"nl":{"statement":"Albert Einstein was gezakt voor wiskunde.","isTrue":"false","explanation":"Einstein had topscores voor wiskunde. Deze mythe is volledig onjuist."},"pl":{"statement":"Albert Einstein oblał matematykę.","isTrue":"false","explanation":"Einstein miał najwyższe oceny z matematyki. Ten mit jest całkowicie fałszywy."},"pt":{"statement":"Albert Einstein reprovou em matemática.","isTrue":"false","explanation":"Einstein teve notas máximas em matemática. Este mito é completamente falso."},"tr":{"statement":"Albert Einstein matematikten kalmıştı.","isTrue":"false","explanation":"Einstein matematikte en yüksek notları almıştı. Bu efsane tamamen yanlıştır."},"ar":{"statement":"ألبرت أينشتاين رسب في الرياضيات.","isTrue":"false","explanation":"حصل أينشتاين على أعلى الدرجات في الرياضيات. هذه الأسطورة خاطئة تماماً."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Spaghetti mit Tomatensosse ist ein traditionelles italienisches Gericht.","isTrue":"false","explanation":"Tomaten kamen erst im 16. Jahrhundert aus Amerika nach Europa. Traditionelle Pasta war anders gewürzt."},"en":{"statement":"Spaghetti with tomato sauce is a traditional Italian dish.","isTrue":"false","explanation":"Tomatoes didn''t arrive in Europe from the Americas until the 16th century. Traditional pasta was seasoned differently."},"es":{"statement":"Los espaguetis con salsa de tomate son un plato italiano tradicional.","isTrue":"false","explanation":"Los tomates no llegaron a Europa desde América hasta el siglo XVI. La pasta tradicional se condimentaba de otra manera."},"fr":{"statement":"Les spaghettis à la sauce tomate sont un plat italien traditionnel.","isTrue":"false","explanation":"Les tomates ne sont arrivées en Europe depuis l\\"},"it":{"statement":"Gli spaghetti al sugo di pomodoro sono un piatto italiano tradizionale.","isTrue":"false","explanation":"I pomodori arrivarono in Europa dalle Americhe solo nel XVI secolo. La pasta tradizionale era condita diversamente."},"nl":{"statement":"Spaghetti met tomatensaus is een traditioneel Italiaans gerecht.","isTrue":"false","explanation":"Tomaten kwamen pas in de 16e eeuw vanuit Amerika naar Europa. Traditionele pasta werd anders gekruid."},"pl":{"statement":"Spaghetti z sosem pomidorowym to tradycyjne danie włoskie.","isTrue":"false","explanation":"Pomidory trafiły do Europy z Ameryki dopiero w XVI wieku. Tradycyjny makaron był przyprawiany inaczej."},"pt":{"statement":"Esparguete com molho de tomate é um prato tradicional italiano.","isTrue":"false","explanation":"Os tomates só chegaram à Europa vindos da América no século XVI. A massa tradicional era temperada de outra forma."},"tr":{"statement":"Domates soslu spagetti geleneksel bir İtalyan yemeğidir.","isTrue":"false","explanation":"Domatesler Avrupa\\"},"ar":{"statement":"السباغيتي بصلصة الطماطم طبق إيطالي تقليدي.","isTrue":"false","explanation":"لم تصل الطماطم إلى أوروبا من أمريكا إلا في القرن السادس عشر. المعكرونة التقليدية كانت متبلة بطريقة مختلفة."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Russland hat elf Zeitzonen.","isTrue":"true","explanation":"Von Kaliningrad bis Kamtschatka erstreckt sich Russland über11 Zeitzonen."},"en":{"statement":"Russia has eleven time zones.","isTrue":"true","explanation":"From Kaliningrad to Kamchatka, Russia spans 11 time zones."},"es":{"statement":"Rusia tiene once husos horarios.","isTrue":"true","explanation":"Desde Kaliningrado hasta Kamchatka, Rusia se extiende por 11 husos horarios."},"fr":{"statement":"La Russie a onze fuseaux horaires.","isTrue":"true","explanation":"De Kaliningrad au Kamtchatka, la Russie s\\"},"it":{"statement":"La Russia ha undici fusi orari.","isTrue":"true","explanation":"Da Kaliningrad alla Kamčatka, la Russia si estende su 11 fusi orari."},"nl":{"statement":"Rusland heeft elf tijdzones.","isTrue":"true","explanation":"Van Kaliningrad tot Kamtsjatka strekt Rusland zich uit over 11 tijdzones."},"pl":{"statement":"Rosja ma jedenaście stref czasowych.","isTrue":"true","explanation":"Od Kaliningradu po Kamczatkę Rosja rozciąga się na 11 stref czasowych."},"pt":{"statement":"A Rússia tem onze fusos horários.","isTrue":"true","explanation":"De Kaliningrado a Kamchatka, a Rússia estende-se por 11 fusos horários."},"tr":{"statement":"Rusya\\","isTrue":"true","explanation":"Kaliningrad\\"},"ar":{"statement":"لدى روسيا أحد عشر منطقة زمنية.","isTrue":"true","explanation":"من كالينينغراد إلى كامتشاتكا تمتد روسيا عبر 11 منطقة زمنية."}}', 'medium', 'Geografie', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Amazonas ist der längste Fluss der Welt.","isTrue":"false","explanation":"Der Nil mit ca. 6.650 km gilt als längster Fluss, der Amazonas ist der wasserreichste."},"en":{"statement":"The Amazon is the longest river in the world.","isTrue":"false","explanation":"The Nile at about 6,650 km is considered the longest river. The Amazon is the largest by volume."},"es":{"statement":"El Amazonas es el río más largo del mundo.","isTrue":"false","explanation":"El Nilo con aprox. 6.650 km es considerado el río más largo, el Amazonas es el de mayor caudal."},"fr":{"statement":"L\\","isTrue":"false","explanation":"Le Nil avec environ 6 650 km est considéré comme le plus long fleuve, l\\"},"it":{"statement":"Il Rio delle Amazzoni è il fiume più lungo del mondo.","isTrue":"false","explanation":"Il Nilo con circa 6.650 km è considerato il più lungo, il Rio delle Amazzoni è quello con il maggior volume d\\"},"nl":{"statement":"De Amazone is de langste rivier ter wereld.","isTrue":"false","explanation":"De Nijl met ca. 6.650 km geldt als langste rivier, de Amazone is de waterrijkste."},"pl":{"statement":"Amazonka jest najdłuższą rzeką na świecie.","isTrue":"false","explanation":"Nil o długości ok. 6650 km uchodzi za najdłuższą rzekę, Amazonka jest najbardziej zasobna w wodę."},"pt":{"statement":"O Amazonas é o rio mais longo do mundo.","isTrue":"false","explanation":"O Nilo, com cerca de 6.650 km, é considerado o rio mais longo; o Amazonas é o mais caudaloso."},"tr":{"statement":"Amazon dünyanın en uzun nehridir.","isTrue":"false","explanation":"Yaklaşık 6.650 km ile Nil en uzun nehir olarak kabul edilir, Amazon ise en çok su taşıyan nehirdir."},"ar":{"statement":"الأمازون هو أطول نهر في العالم.","isTrue":"false","explanation":"يُعتبر النيل بطول حوالي 6,650 كم أطول نهر، بينما الأمازون هو الأغزر."}}', 'medium', 'Geografie', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Island hat keine Muecken.","isTrue":"true","explanation":"Island ist tatsächlich eines der wenigen Länder weltweit ohne heimische Mueckenarten."},"en":{"statement":"Iceland has no mosquitoes.","isTrue":"true","explanation":"Iceland is actually one of the few countries in the world with no native mosquito species."},"es":{"statement":"Islandia no tiene mosquitos.","isTrue":"true","explanation":"Islandia es uno de los pocos países del mundo sin especies de mosquitos autóctonas."},"fr":{"statement":"L\\","isTrue":"true","explanation":"L\\"},"it":{"statement":"L\\","isTrue":"true","explanation":"L\\"},"nl":{"statement":"IJsland heeft geen muggen.","isTrue":"true","explanation":"IJsland is daadwerkelijk een van de weinige landen ter wereld zonder inheemse muggensoorten."},"pl":{"statement":"Islandia nie ma komarów.","isTrue":"true","explanation":"Islandia jest rzeczywiście jednym z nielicznych krajów na świecie bez rodzimych gatunków komarów."},"pt":{"statement":"A Islândia não tem mosquitos.","isTrue":"true","explanation":"A Islândia é de facto um dos poucos países do mundo sem espécies nativas de mosquitos."},"tr":{"statement":"İzlanda\\","isTrue":"true","explanation":"İzlanda gerçekten de yerli sivrisinek türü olmayan dünyadaki birkaç ülkeden biridir."},"ar":{"statement":"لا يوجد بعوض في أيسلندا.","isTrue":"true","explanation":"أيسلندا هي فعلاً واحدة من البلدان القليلة في العالم التي لا توجد فيها أنواع بعوض محلية."}}', 'medium', 'Geografie', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Die Sahara ist die größte Wüste der Welt.","isTrue":"false","explanation":"Die Antarktis ist die größte Wüste (14 Mio. km²). Die Sahara ist die größte Heisswueste."},"en":{"statement":"The Sahara is the largest desert in the world.","isTrue":"false","explanation":"Antarctica is the largest desert (14 million km\\u00B2). The Sahara is the largest hot desert."},"es":{"statement":"El Sahara es el desierto más grande del mundo.","isTrue":"false","explanation":"La Antártida es el desierto más grande (14 mill. km²). El Sahara es el desierto cálido más grande."},"fr":{"statement":"Le Sahara est le plus grand désert du monde.","isTrue":"false","explanation":"L\\"},"it":{"statement":"Il Sahara è il deserto più grande del mondo.","isTrue":"false","explanation":"L\\"},"nl":{"statement":"De Sahara is de grootste woestijn ter wereld.","isTrue":"false","explanation":"Antarctica is de grootste woestijn (14 mln. km²). De Sahara is de grootste hete woestijn."},"pl":{"statement":"Sahara jest największą pustynią na świecie.","isTrue":"false","explanation":"Antarktyda jest największą pustynią (14 mln km²). Sahara jest największą pustynią gorącą."},"pt":{"statement":"O Saara é o maior deserto do mundo.","isTrue":"false","explanation":"A Antártida é o maior deserto (14 milhões de km²). O Saara é o maior deserto quente."},"tr":{"statement":"Sahra dünyanın en büyük çölüdür.","isTrue":"false","explanation":"Antarktika en büyük çöldür (14 milyon km²). Sahra en büyük sıcak çöldür."},"ar":{"statement":"الصحراء الكبرى هي أكبر صحراء في العالم.","isTrue":"false","explanation":"القارة القطبية الجنوبية هي أكبر صحراء (14 مليون كم²). الصحراء الكبرى هي أكبر صحراء حارة."}}', 'medium', 'Geografie', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"In Australien gibt es mehr Kängurus als Menschen.","isTrue":"true","explanation":"Es gibt ca. 50 Millionen Kängurus bei 26 Millionen Menschen in Australien."},"en":{"statement":"In Australia, there are more kangaroos than people.","isTrue":"true","explanation":"There are about 50 million kangaroos compared to 26 million people in Australia."},"es":{"statement":"En Australia hay más canguros que personas.","isTrue":"true","explanation":"Hay unos 50 millones de canguros frente a 26 millones de personas en Australia."},"fr":{"statement":"En Australie, il y a plus de kangourous que d\\","isTrue":"true","explanation":"Il y a environ 50 millions de kangourous pour 26 millions d\\"},"it":{"statement":"In Australia ci sono più canguri che persone.","isTrue":"true","explanation":"Ci sono circa 50 milioni di canguri a fronte di 26 milioni di persone in Australia."},"nl":{"statement":"In Australië zijn er meer kangoeroes dan mensen.","isTrue":"true","explanation":"Er zijn ca. 50 miljoen kangoeroes bij 26 miljoen mensen in Australië."},"pl":{"statement":"W Australii jest więcej kangurów niż ludzi.","isTrue":"true","explanation":"Jest ok. 50 milionów kangurów przy 26 milionach ludzi w Australii."},"pt":{"statement":"Na Austrália há mais cangurus do que pessoas.","isTrue":"true","explanation":"Existem cerca de 50 milhões de cangurus para 26 milhões de pessoas na Austrália."},"tr":{"statement":"Avustralya\\","isTrue":"true","explanation":"Avustralya\\"},"ar":{"statement":"في أستراليا عدد الكنغر أكثر من عدد البشر.","isTrue":"true","explanation":"يوجد حوالي 50 مليون كنغر مقابل 26 مليون شخص في أستراليا."}}', 'medium', 'Geografie', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Mount Everest ist der höchste Berg vom Erdmittelpunkt aus gemessen.","isTrue":"false","explanation":"Der Chimborazo in Ecuador ist dem Erdmittelpunkt am weitesten entfernt, weil die Erde am Aequator dicker ist."},"en":{"statement":"Mount Everest is the tallest mountain measured from the center of the Earth.","isTrue":"false","explanation":"Chimborazo in Ecuador is farthest from Earth''s center because the Earth bulges at the equator."},"es":{"statement":"El Monte Everest es la montaña más alta medida desde el centro de la Tierra.","isTrue":"false","explanation":"El Chimborazo en Ecuador es el punto más alejado del centro de la Tierra, porque la Tierra es más ancha en el ecuador."},"fr":{"statement":"Le Mont Everest est la montagne la plus haute mesurée depuis le centre de la Terre.","isTrue":"false","explanation":"Le Chimborazo en Équateur est le point le plus éloigné du centre de la Terre, car la Terre est plus large à l\\"},"it":{"statement":"Il Monte Everest è la montagna più alta misurata dal centro della Terra.","isTrue":"false","explanation":"Il Chimborazo in Ecuador è il punto più lontano dal centro della Terra, perché la Terra è più larga all\\"},"nl":{"statement":"De Mount Everest is de hoogste berg gemeten vanuit het middelpunt van de aarde.","isTrue":"false","explanation":"De Chimborazo in Ecuador is het verst verwijderd van het middelpunt van de aarde, omdat de aarde bij de evenaar dikker is."},"pl":{"statement":"Mount Everest jest najwyższą górą mierzoną od środka Ziemi.","isTrue":"false","explanation":"Chimborazo w Ekwadorze jest najbardziej oddalony od środka Ziemi, ponieważ Ziemia jest grubsza na równiku."},"pt":{"statement":"O Monte Evereste é a montanha mais alta medida a partir do centro da Terra.","isTrue":"false","explanation":"O Chimborazo, no Equador, é o ponto mais distante do centro da Terra, porque a Terra é mais espessa no equador."},"tr":{"statement":"Everest Dağı, Dünya\\","isTrue":"false","explanation":"Ekvador\\"},"ar":{"statement":"جبل إيفرست هو أعلى جبل قياساً من مركز الأرض.","isTrue":"false","explanation":"جبل شيمبورازو في الإكوادور هو الأبعد عن مركز الأرض لأن الأرض أسمك عند خط الاستواء."}}', 'medium', 'Geografie', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"In der Schweiz ist es illegal, nur ein Meerschweinchen zu halten.","isTrue":"true","explanation":"Meerschweinchen sind soziale Tiere. Schweizer Tierschutzgesetze verbieten Einzelhaltung."},"en":{"statement":"In Switzerland, it is illegal to keep just one guinea pig.","isTrue":"true","explanation":"Guinea pigs are social animals. Swiss animal protection laws prohibit keeping them alone."},"es":{"statement":"En Suiza es ilegal tener un solo cobaya.","isTrue":"true","explanation":"Los cobayas son animales sociales. Las leyes suizas de protección animal prohíben tenerlos solos."},"fr":{"statement":"En Suisse, il est illégal de ne posséder qu\\","isTrue":"true","explanation":"Les cochons d\\"},"it":{"statement":"In Svizzera è illegale possedere una sola cavia.","isTrue":"true","explanation":"Le cavie sono animali sociali. Le leggi svizzere sulla protezione degli animali ne vietano il possesso singolo."},"nl":{"statement":"In Zwitserland is het illegaal om slechts één cavia te houden.","isTrue":"true","explanation":"Cavia\\"},"pl":{"statement":"W Szwajcarii nielegalne jest posiadanie tylko jednej świnki morskiej.","isTrue":"true","explanation":"Świnki morskie to zwierzęta stadne. Szwajcarskie prawo ochrony zwierząt zabrania trzymania ich pojedynczo."},"pt":{"statement":"Na Suíça, é ilegal ter apenas um porquinho-da-índia.","isTrue":"true","explanation":"Os porquinhos-da-índia são animais sociais. As leis suíças de proteção animal proíbem mantê-los sozinhos."},"tr":{"statement":"İsviçre\\","isTrue":"true","explanation":"Kobaylar sosyal hayvanlardır. İsviçre hayvan koruma yasaları tek başına beslemeyi yasaklar."},"ar":{"statement":"في سويسرا من غير القانوني تربية خنزير غينيا واحد فقط.","isTrue":"true","explanation":"خنازير غينيا حيوانات اجتماعية. قوانين حماية الحيوان السويسرية تحظر تربيتها بمفردها."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Es gibt mehr Sterne im Universum als Sandkoerner auf der Erde.","isTrue":"true","explanation":"Schätzungen: ca. 10^24 Sterne im beobachtbaren Universum, ca. 7.5×10^18 Sandkoerner."},"en":{"statement":"There are more stars in the universe than grains of sand on Earth.","isTrue":"true","explanation":"Estimates: about 10^24 stars in the observable universe, about 7.5x10^18 grains of sand."},"es":{"statement":"Hay más estrellas en el universo que granos de arena en la Tierra.","isTrue":"true","explanation":"Estimaciones: aprox. 10^24 estrellas en el universo observable, aprox. 7,5×10^18 granos de arena."},"fr":{"statement":"Il y a plus d\\","isTrue":"true","explanation":"Estimations : environ 10^24 étoiles dans l\\"},"it":{"statement":"Ci sono più stelle nell\\","isTrue":"true","explanation":"Stime: circa 10^24 stelle nell\\"},"nl":{"statement":"Er zijn meer sterren in het universum dan zandkorrels op aarde.","isTrue":"true","explanation":"Schattingen: ca. 10^24 sterren in het waarneembare universum, ca. 7,5×10^18 zandkorrels."},"pl":{"statement":"We wszechświecie jest więcej gwiazd niż ziarenek piasku na Ziemi.","isTrue":"true","explanation":"Szacunki: ok. 10^24 gwiazd w obserwowalnym wszechświecie, ok. 7,5×10^18 ziarenek piasku."},"pt":{"statement":"Existem mais estrelas no universo do que grãos de areia na Terra.","isTrue":"true","explanation":"Estimativas: cerca de 10^24 estrelas no universo observável, cerca de 7,5×10^18 grãos de areia."},"tr":{"statement":"Evrende, Dünya\\","isTrue":"true","explanation":"Tahminler: gözlemlenebilir evrende yaklaşık 10^24 yıldız, yaklaşık 7,5×10^18 kum tanesi."},"ar":{"statement":"عدد النجوم في الكون أكثر من عدد حبات الرمل على الأرض.","isTrue":"true","explanation":"التقديرات: حوالي 10^24 نجمة في الكون المرصود، وحوالي 7.5×10^18 حبة رمل."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Eine Schnecke kann bis zu 3 Jahre schlafen.","isTrue":"true","explanation":"Manche Schneckenarten können in einen langanhaltenden Ruhezustand fallen, besonders bei Trockenheit."},"en":{"statement":"A snail can sleep for up to 3 years.","isTrue":"true","explanation":"Some snail species can enter a prolonged dormant state, especially during dry periods."},"es":{"statement":"Un caracol puede dormir hasta 3 años.","isTrue":"true","explanation":"Algunas especies de caracoles pueden entrar en un estado de reposo prolongado, especialmente durante la sequía."},"fr":{"statement":"Un escargot peut dormir jusqu\\","isTrue":"true","explanation":"Certaines espèces d\\"},"it":{"statement":"Una lumaca può dormire fino a 3 anni.","isTrue":"true","explanation":"Alcune specie di lumache possono entrare in uno stato di riposo prolungato, specialmente durante la siccità."},"nl":{"statement":"Een slak kan tot 3 jaar slapen.","isTrue":"true","explanation":"Sommige slakkensoorten kunnen in een langdurige ruststand vallen, vooral bij droogte."},"pl":{"statement":"Ślimak może spać nawet 3 lata.","isTrue":"true","explanation":"Niektóre gatunki ślimaków mogą popadać w długotrwały stan spoczynku, szczególnie w czasie suszy."},"pt":{"statement":"Um caracol pode dormir até 3 anos.","isTrue":"true","explanation":"Algumas espécies de caracóis podem entrar num estado prolongado de dormência, especialmente em períodos de seca."},"tr":{"statement":"Bir salyangoz 3 yıla kadar uyuyabilir.","isTrue":"true","explanation":"Bazı salyangoz türleri, özellikle kurak dönemlerde uzun süreli uyku haline geçebilir."},"ar":{"statement":"يمكن للحلزون أن ينام لمدة تصل إلى 3 سنوات.","isTrue":"true","explanation":"بعض أنواع الحلزون يمكنها الدخول في حالة سبات طويلة، خاصة في فترات الجفاف."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Erfinder der Pringles-Dose ist in einer begraben.","isTrue":"true","explanation":"Fredric Baur, der Erfinder der Pringles-Dose, wurde 2008 auf eigenen Wunsch in einer bestattet."},"en":{"statement":"The inventor of the Pringles can is buried in one.","isTrue":"true","explanation":"Fredric Baur, the inventor of the Pringles can, was buried in one at his own request in 2008."},"es":{"statement":"El inventor del envase de Pringles fue enterrado en uno.","isTrue":"true","explanation":"Fredric Baur, el inventor del envase de Pringles, fue enterrado en uno en 2008 por deseo propio."},"fr":{"statement":"L\\","isTrue":"true","explanation":"Fredric Baur, l\\"},"it":{"statement":"L\\","isTrue":"true","explanation":"Fredric Baur, l\\"},"nl":{"statement":"De uitvinder van de Pringles-bus is erin begraven.","isTrue":"true","explanation":"Fredric Baur, de uitvinder van de Pringles-bus, werd in 2008 op eigen verzoek erin begraven."},"pl":{"statement":"Wynalazca puszki Pringles został w niej pochowany.","isTrue":"true","explanation":"Fredric Baur, wynalazca puszki Pringles, został w 2008 r. na własne życzenie w niej pochowany."},"pt":{"statement":"O inventor da embalagem de Pringles foi enterrado numa.","isTrue":"true","explanation":"Fredric Baur, o inventor da embalagem de Pringles, foi enterrado numa em 2008, a seu pedido."},"tr":{"statement":"Pringles kutusunun mucidi bir tanesinin içine gömüldü.","isTrue":"true","explanation":"Fredric Baur, Pringles kutusunun mucidi, 2008\\"},"ar":{"statement":"مخترع علبة برينغلز دُفن في واحدة منها.","isTrue":"true","explanation":"فريدريك باور، مخترع علبة برينغلز، دُفن في واحدة منها عام 2008 بناءً على رغبته."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Kühe können Treppen hinaufsteigen, aber nicht hinunter.","isTrue":"true","explanation":"Aufgrund ihrer Kniestruktur und ihres Sichtfelds können Kühe Treppen nicht sicher hinabsteigen."},"en":{"statement":"Cows can walk up stairs but not down them.","isTrue":"true","explanation":"Due to their knee structure and field of vision, cows cannot safely walk down stairs."},"es":{"statement":"Las vacas pueden subir escaleras, pero no bajarlas.","isTrue":"true","explanation":"Debido a la estructura de sus rodillas y su campo de visión, las vacas no pueden bajar escaleras de forma segura."},"fr":{"statement":"Les vaches peuvent monter les escaliers, mais pas les descendre.","isTrue":"true","explanation":"En raison de la structure de leurs genoux et de leur champ de vision, les vaches ne peuvent pas descendre les escaliers en toute sécurité."},"it":{"statement":"Le mucche possono salire le scale, ma non scenderle.","isTrue":"true","explanation":"A causa della struttura delle ginocchia e del campo visivo, le mucche non possono scendere le scale in sicurezza."},"nl":{"statement":"Koeien kunnen trappen oplopen, maar niet afdalen.","isTrue":"true","explanation":"Door hun kniestructuur en gezichtsveld kunnen koeien niet veilig trappen afdalen."},"pl":{"statement":"Krowy mogą wchodzić po schodach, ale nie mogą po nich schodzić.","isTrue":"true","explanation":"Ze względu na budowę kolan i pole widzenia krowy nie mogą bezpiecznie schodzić po schodach."},"pt":{"statement":"As vacas conseguem subir escadas, mas não descer.","isTrue":"true","explanation":"Devido à estrutura dos joelhos e ao campo de visão, as vacas não conseguem descer escadas em segurança."},"tr":{"statement":"İnekler merdiven çıkabilir ama inemez.","isTrue":"true","explanation":"Diz yapıları ve görüş alanları nedeniyle inekler merdivenlerden güvenli şekilde inemez."},"ar":{"statement":"الأبقار تستطيع صعود الدرج لكن لا تستطيع نزوله.","isTrue":"true","explanation":"بسبب تركيب ركبها ومجال رؤيتها، لا تستطيع الأبقار نزول الدرج بأمان."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Jeder Mensch verschluckt im Schlaf durchschnittlich 8 Spinnen pro Jahr.","isTrue":"false","explanation":"Dieser Mythos wurde 1993 absichtlich als Beispiel fürFake-Fakten erfunden."},"en":{"statement":"The average person swallows 8 spiders per year in their sleep.","isTrue":"false","explanation":"This myth was deliberately invented in 1993 as an example of how fake facts spread online."},"es":{"statement":"Cada persona se traga un promedio de 8 arañas al año mientras duerme.","isTrue":"false","explanation":"Este mito fue inventado en 1993 a propósito como ejemplo de datos falsos."},"fr":{"statement":"Chaque personne avale en moyenne 8 araignées par an dans son sommeil.","isTrue":"false","explanation":"Ce mythe a été inventé en 1993 volontairement comme exemple de fausse information."},"it":{"statement":"Ogni persona inghiotte in media 8 ragni all\\","isTrue":"false","explanation":"Questo mito è stato inventato nel 1993 di proposito come esempio di notizia falsa."},"nl":{"statement":"Ieder mens slikt gemiddeld 8 spinnen per jaar in tijdens de slaap.","isTrue":"false","explanation":"Deze mythe werd in 1993 opzettelijk verzonnen als voorbeeld van nepfeiten."},"pl":{"statement":"Każdy człowiek połyka średnio 8 pająków rocznie podczas snu.","isTrue":"false","explanation":"Ten mit został w 1993 r. celowo wymyślony jako przykład fałszywych faktów."},"pt":{"statement":"Cada pessoa engole em média 8 aranhas por ano durante o sono.","isTrue":"false","explanation":"Este mito foi inventado propositadamente em 1993 como exemplo de factos falsos."},"tr":{"statement":"Her insan uykuda yılda ortalama 8 örümcek yutar.","isTrue":"false","explanation":"Bu efsane 1993\\"},"ar":{"statement":"يبتلع كل إنسان في المتوسط 8 عناكب سنوياً أثناء النوم.","isTrue":"false","explanation":"هذه الأسطورة اختُرعت عمداً عام 1993 كمثال على الحقائق المزيفة."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Hummeln duerfen laut Physik eigentlich nicht fliegen.","isTrue":"false","explanation":"Dieses Gerücht basiert auf falschen Berechnungen. Die Aerodynamik von Hummelflug ist laengst erklaert."},"en":{"statement":"According to physics, bumblebees shouldn''t be able to fly.","isTrue":"false","explanation":"This rumor is based on flawed calculations. The aerodynamics of bumblebee flight have long been explained."},"es":{"statement":"Según la física, los abejorros no deberían poder volar.","isTrue":"false","explanation":"Este rumor se basa en cálculos erróneos. La aerodinámica del vuelo del abejorro está explicada desde hace tiempo."},"fr":{"statement":"Selon la physique, les bourdons ne devraient pas pouvoir voler.","isTrue":"false","explanation":"Cette rumeur repose sur des calculs erronés. L\\"},"it":{"statement":"Secondo la fisica, i bombi non dovrebbero poter volare.","isTrue":"false","explanation":"Questa diceria si basa su calcoli errati. L\\"},"nl":{"statement":"Hommels kunnen volgens de natuurkunde eigenlijk niet vliegen.","isTrue":"false","explanation":"Dit gerucht is gebaseerd op foutieve berekeningen. De aerodynamica van hommelvlucht is allang verklaard."},"pl":{"statement":"Trzmiele według praw fizyki nie powinny latać.","isTrue":"false","explanation":"Ta plotka opiera się na błędnych obliczeniach. Aerodynamika lotu trzmiela została dawno wyjaśniona."},"pt":{"statement":"Os abelhões não deveriam conseguir voar segundo a física.","isTrue":"false","explanation":"Este boato baseia-se em cálculos errados. A aerodinâmica do voo do abelhão já foi explicada há muito."},"tr":{"statement":"Fiziğe göre yaban arıları aslında uçamamalıdır.","isTrue":"false","explanation":"Bu söylenti yanlış hesaplamalara dayanır. Yaban arısı uçuşunun aerodinamiği çoktan açıklanmıştır."},"ar":{"statement":"وفقاً لقوانين الفيزياء، لا ينبغي للنحل الطنان أن يطير.","isTrue":"false","explanation":"هذه الشائعة مبنية على حسابات خاطئة. ديناميكا طيران النحل الطنان مفسَّرة منذ زمن."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"In Japan gibt es einen Insel voller Katzen, auf der sie die Menschen überwiegen.","isTrue":"true","explanation":"Aoshima, auch Katzeninsel genannt, hat etwa 6:1 Katzen-zu-Menschen-Verhältnis."},"en":{"statement":"In Japan, there is an island full of cats that outnumber the humans.","isTrue":"true","explanation":"Aoshima, also known as Cat Island, has roughly a 6:1 cat-to-human ratio."},"es":{"statement":"En Japón hay una isla llena de gatos donde superan en número a los humanos.","isTrue":"true","explanation":"Aoshima, también conocida como la Isla de los Gatos, tiene una proporción de aproximadamente 6:1 gatos por persona."},"fr":{"statement":"Au Japon, il y a une île pleine de chats où ils sont plus nombreux que les humains.","isTrue":"true","explanation":"Aoshima, aussi appelée l\\"},"it":{"statement":"In Giappone c\\","isTrue":"true","explanation":"Aoshima, nota anche come Isola dei Gatti, ha un rapporto di circa 6 gatti per 1 persona."},"nl":{"statement":"In Japan is er een eiland vol katten, waar ze de mensen in aantal overtreffen.","isTrue":"true","explanation":"Aoshima, ook wel katteneiland genoemd, heeft een verhouding van ongeveer 6:1 katten ten opzichte van mensen."},"pl":{"statement":"W Japonii istnieje wyspa pełna kotów, gdzie przewyższają one liczbę ludzi.","isTrue":"true","explanation":"Aoshima, zwana też wyspą kotów, ma stosunek kotów do ludzi wynoszący ok. 6:1."},"pt":{"statement":"No Japão existe uma ilha cheia de gatos, onde superam os humanos em número.","isTrue":"true","explanation":"Aoshima, também chamada ilha dos gatos, tem uma proporção de cerca de 6:1 de gatos para pessoas."},"tr":{"statement":"Japonya\\","isTrue":"true","explanation":"Kedi adası olarak da bilinen Aoshima\\"},"ar":{"statement":"في اليابان جزيرة مليئة بالقطط حيث يفوق عددها عدد البشر.","isTrue":"true","explanation":"أوشيما، المعروفة أيضاً بجزيرة القطط، فيها نسبة قطط إلى بشر تبلغ حوالي 6:1."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der kuerzeste Krieg der Geschichte dauerte 38 Minuten.","isTrue":"true","explanation":"Der Anglo-Sansibar-Krieg 1896 dauerte zwischen 38 und 45 Minuten."},"en":{"statement":"The shortest war in history lasted 38 minutes.","isTrue":"true","explanation":"The Anglo-Zanzibar War of 1896 lasted between 38 and 45 minutes."},"es":{"statement":"La guerra más corta de la historia duró 38 minutos.","isTrue":"true","explanation":"La guerra anglo-zanzibarí de 1896 duró entre 38 y 45 minutos."},"fr":{"statement":"La guerre la plus courte de l\\","isTrue":"true","explanation":"La guerre anglo-zanzibarite de 1896 a duré entre 38 et 45 minutes."},"it":{"statement":"La guerra più breve della storia è durata 38 minuti.","isTrue":"true","explanation":"La guerra anglo-zanzibariana del 1896 durò tra i 38 e i 45 minuti."},"nl":{"statement":"De kortste oorlog in de geschiedenis duurde 38 minuten.","isTrue":"true","explanation":"De Anglo-Zanzibar oorlog van 1896 duurde tussen de 38 en 45 minuten."},"pl":{"statement":"Najkrótsza wojna w historii trwała 38 minut.","isTrue":"true","explanation":"Wojna anglo-zanzibaryjska w 1896 r. trwała od 38 do 45 minut."},"pt":{"statement":"A guerra mais curta da história durou 38 minutos.","isTrue":"true","explanation":"A Guerra Anglo-Zanzibar de 1896 durou entre 38 e 45 minutos."},"tr":{"statement":"Tarihin en kısa savaşı 38 dakika sürmüştür.","isTrue":"true","explanation":"1896 İngiliz-Zanzibar Savaşı 38 ile 45 dakika arasında sürmüştür."},"ar":{"statement":"أقصر حرب في التاريخ استمرت 38 دقيقة.","isTrue":"true","explanation":"الحرب الأنغلو-زنجبارية عام 1896 استمرت بين 38 و45 دقيقة."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Flamingos sind von Geburt an rosa.","isTrue":"false","explanation":"Flamingos werden grau-weiss geboren und faerben sich durch ihre Nahrung (Krebstiere, Algen) rosa."},"en":{"statement":"Flamingos are born pink.","isTrue":"false","explanation":"Flamingos are born grey-white and turn pink from their diet of crustaceans and algae."},"es":{"statement":"Los flamencos son rosados de nacimiento.","isTrue":"false","explanation":"Los flamencos nacen gris-blancos y se vuelven rosados por su alimentación (crustáceos, algas)."},"fr":{"statement":"Les flamants roses sont roses dès la naissance.","isTrue":"false","explanation":"Les flamants naissent gris-blanc et deviennent roses grâce à leur alimentation (crustacés, algues)."},"it":{"statement":"I fenicotteri sono rosa dalla nascita.","isTrue":"false","explanation":"I fenicotteri nascono grigio-bianchi e diventano rosa grazie alla loro alimentazione (crostacei, alghe)."},"nl":{"statement":"Flamingo\\","isTrue":"false","explanation":"Flamingo\\"},"pl":{"statement":"Flamingi rodzą się różowe.","isTrue":"false","explanation":"Flamingi rodzą się szaro-białe i nabierają różowego koloru dzięki pożywieniu (skorupiaki, glony)."},"pt":{"statement":"Os flamingos nascem cor-de-rosa.","isTrue":"false","explanation":"Os flamingos nascem cinzento-esbranquiçados e ficam cor-de-rosa devido à alimentação (crustáceos, algas)."},"tr":{"statement":"Flamingolar doğuştan pembedir.","isTrue":"false","explanation":"Flamingolar gri-beyaz doğar ve besinleri (kabuklu deniz hayvanları, yosunlar) sayesinde pembeye döner."},"ar":{"statement":"طيور الفلامنغو تولد باللون الوردي.","isTrue":"false","explanation":"تولد طيور الفلامنغو بلون رمادي-أبيض وتكتسب اللون الوردي من غذائها (القشريات والطحالب)."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Das erste iPhone hatte keinen App Store.","isTrue":"true","explanation":"Das erste iPhone kam 2007 heraus, der App Store wurde erst 2008 eingeführt."},"en":{"statement":"The first iPhone didn''t have an App Store.","isTrue":"true","explanation":"The first iPhone launched in 2007, but the App Store was not introduced until 2008."},"es":{"statement":"El primer iPhone no tenía App Store.","isTrue":"true","explanation":"El primer iPhone salió en 2007, la App Store no se lanzó hasta 2008."},"fr":{"statement":"Le premier iPhone n\\","isTrue":"true","explanation":"Le premier iPhone est sorti en 2007, l\\"},"it":{"statement":"Il primo iPhone non aveva l\\","isTrue":"true","explanation":"Il primo iPhone uscì nel 2007, l\\"},"nl":{"statement":"De eerste iPhone had geen App Store.","isTrue":"true","explanation":"De eerste iPhone kwam in 2007 uit, de App Store werd pas in 2008 gelanceerd."},"pl":{"statement":"Pierwszy iPhone nie miał App Store\\","isTrue":"true","explanation":"Pierwszy iPhone pojawił się w 2007 r., App Store został uruchomiony dopiero w 2008 r."},"pt":{"statement":"O primeiro iPhone não tinha App Store.","isTrue":"true","explanation":"O primeiro iPhone saiu em 2007, a App Store só foi lançada em 2008."},"tr":{"statement":"İlk iPhone\\","isTrue":"true","explanation":"İlk iPhone 2007\\"},"ar":{"statement":"أول آيفون لم يكن فيه متجر تطبيقات.","isTrue":"true","explanation":"صدر أول آيفون عام 2007، بينما لم يُطلق متجر التطبيقات إلا عام 2008."}}', 'medium', 'Technik', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Die erste SMS der Welt lautete \"Merry Christmas\".","isTrue":"true","explanation":"Am 3. Dezember 1992 schickte Neil Papworth die erste SMS mit dem Text \"Merry Christmas\"."},"en":{"statement":"The first SMS ever sent said \"Merry Christmas\".","isTrue":"true","explanation":"On December 3, 1992, Neil Papworth sent the first SMS with the text \"Merry Christmas\"."},"es":{"statement":"El primer SMS del mundo decía \"Merry Christmas\".","isTrue":"true","explanation":"El 3 de diciembre de 1992, Neil Papworth envió el primer SMS con el texto \"Merry Christmas\"."},"fr":{"statement":"Le premier SMS au monde disait \"Merry Christmas\".","isTrue":"true","explanation":"Le 3 décembre 1992, Neil Papworth a envoyé le premier SMS avec le texte \"Merry Christmas\"."},"it":{"statement":"Il primo SMS al mondo diceva \"Merry Christmas\".","isTrue":"true","explanation":"Il 3 dicembre 1992, Neil Papworth inviò il primo SMS con il testo \"Merry Christmas\"."},"nl":{"statement":"Het eerste sms-bericht ter wereld luidde \"Merry Christmas\".","isTrue":"true","explanation":"Op 3 december 1992 verstuurde Neil Papworth het eerste sms-bericht met de tekst \"Merry Christmas\"."},"pl":{"statement":"Pierwszy SMS na świecie brzmiał \"Merry Christmas\".","isTrue":"true","explanation":"3 grudnia 1992 r. Neil Papworth wysłał pierwszego SMS-a o treści \"Merry Christmas\"."},"pt":{"statement":"A primeira SMS do mundo dizia \"Merry Christmas\".","isTrue":"true","explanation":"A 3 de dezembro de 1992, Neil Papworth enviou a primeira SMS com o texto \"Merry Christmas\"."},"tr":{"statement":"Dünyanın ilk SMS\\","isTrue":"true","explanation":"3 Aralık 1992\\"},"ar":{"statement":"أول رسالة نصية قصيرة في العالم كانت \"Merry Christmas\".","isTrue":"true","explanation":"في 3 ديسمبر 1992 أرسل نيل بابوورث أول رسالة نصية بنص \"Merry Christmas\"."}}', 'medium', 'Technik', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"WiFi steht fürWireless Fidelity.","isTrue":"false","explanation":"WiFi ist ein Markenname und steht fürnichts. Es wurde von einer Marketingfirma erfunden."},"en":{"statement":"WiFi stands for Wireless Fidelity.","isTrue":"false","explanation":"WiFi is a brand name and doesn''t stand for anything. It was coined by a marketing firm."},"es":{"statement":"WiFi significa Wireless Fidelity.","isTrue":"false","explanation":"WiFi es un nombre de marca y no significa nada. Fue inventado por una empresa de marketing."},"fr":{"statement":"WiFi signifie Wireless Fidelity.","isTrue":"false","explanation":"WiFi est un nom de marque et ne signifie rien. Il a été inventé par une société de marketing."},"it":{"statement":"WiFi sta per Wireless Fidelity.","isTrue":"false","explanation":"WiFi è un nome commerciale e non sta per nulla. È stato inventato da un\\"},"nl":{"statement":"WiFi staat voor Wireless Fidelity.","isTrue":"false","explanation":"WiFi is een merknaam en staat nergens voor. Het werd bedacht door een marketingbureau."},"pl":{"statement":"WiFi oznacza Wireless Fidelity.","isTrue":"false","explanation":"WiFi to nazwa handlowa, która nic nie oznacza. Została wymyślona przez firmę marketingową."},"pt":{"statement":"WiFi significa Wireless Fidelity.","isTrue":"false","explanation":"WiFi é uma marca registada e não significa nada. Foi inventada por uma empresa de marketing."},"tr":{"statement":"WiFi, Wireless Fidelity anlamına gelir.","isTrue":"false","explanation":"WiFi bir marka adıdır ve hiçbir şeyin kısaltması değildir. Bir pazarlama firması tarafından yaratılmıştır."},"ar":{"statement":"WiFi تعني Wireless Fidelity.","isTrue":"false","explanation":"WiFi هو اسم تجاري ولا يرمز إلى أي شيء. ابتكرته شركة تسويق."}}', 'medium', 'Technik', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der erste Computer war so groß wie ein Raum.","isTrue":"true","explanation":"ENIAC (1945) wog 27 Tonnen und belegte 167 Quadratmeter."},"en":{"statement":"The first computer was as big as a room.","isTrue":"true","explanation":"ENIAC (1945) weighed 27 tons and occupied 167 square meters."},"es":{"statement":"El primer ordenador era tan grande como una habitación.","isTrue":"true","explanation":"ENIAC (1945) pesaba 27 toneladas y ocupaba 167 metros cuadrados."},"fr":{"statement":"Le premier ordinateur était aussi grand qu\\","isTrue":"true","explanation":"L\\"},"it":{"statement":"Il primo computer era grande quanto una stanza.","isTrue":"true","explanation":"L\\"},"nl":{"statement":"De eerste computer was zo groot als een kamer.","isTrue":"true","explanation":"ENIAC (1945) woog 27 ton en besloeg 167 vierkante meter."},"pl":{"statement":"Pierwszy komputer był wielkości pokoju.","isTrue":"true","explanation":"ENIAC (1945) ważył 27 ton i zajmował 167 metrów kwadratowych."},"pt":{"statement":"O primeiro computador era do tamanho de uma sala.","isTrue":"true","explanation":"O ENIAC (1945) pesava 27 toneladas e ocupava 167 metros quadrados."},"tr":{"statement":"İlk bilgisayar bir oda büyüklüğündeydi.","isTrue":"true","explanation":"ENIAC (1945) 27 ton ağırlığındaydı ve 167 metrekare yer kaplıyordu."},"ar":{"statement":"أول حاسوب كان بحجم غرفة.","isTrue":"true","explanation":"جهاز ENIAC عام 1945 كان يزن 27 طناً ويشغل 167 متراً مربعاً."}}', 'medium', 'Technik', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"E-Mails verbrauchen keinen Strom.","isTrue":"false","explanation":"Jede E-Mail verbraucht ca. 4g CO2, da Server und Netzwerke Energie benoetigen."},"en":{"statement":"Emails don''t use any electricity.","isTrue":"false","explanation":"Each email produces about 4g of CO2, since servers and networks require energy."},"es":{"statement":"Los correos electrónicos no consumen electricidad.","isTrue":"false","explanation":"Cada correo electrónico consume aprox. 4g de CO2, ya que los servidores y las redes necesitan energía."},"fr":{"statement":"Les e-mails ne consomment pas d\\","isTrue":"false","explanation":"Chaque e-mail consomme environ 4 g de CO2, car les serveurs et les réseaux ont besoin d\\"},"it":{"statement":"Le e-mail non consumano elettricità.","isTrue":"false","explanation":"Ogni e-mail consuma circa 4 g di CO2, poiché i server e le reti necessitano di energia."},"nl":{"statement":"E-mails verbruiken geen stroom.","isTrue":"false","explanation":"Elke e-mail verbruikt ca. 4g CO2, omdat servers en netwerken energie nodig hebben."},"pl":{"statement":"E-maile nie zużywają prądu.","isTrue":"false","explanation":"Każdy e-mail generuje ok. 4 g CO2, ponieważ serwery i sieci potrzebują energii."},"pt":{"statement":"Os e-mails não consomem eletricidade.","isTrue":"false","explanation":"Cada e-mail gera cerca de 4 g de CO2, pois servidores e redes precisam de energia."},"tr":{"statement":"E-postalar elektrik tüketmez.","isTrue":"false","explanation":"Her e-posta yaklaşık 4 g CO2 üretir çünkü sunucular ve ağlar enerji gerektirir."},"ar":{"statement":"البريد الإلكتروني لا يستهلك كهرباء.","isTrue":"false","explanation":"كل رسالة بريد إلكتروني تنتج حوالي 4 غرام من CO2 لأن الخوادم والشبكات تحتاج إلى طاقة."}}', 'medium', 'Technik', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Wombats produzieren wuerfelfoemigen Kot.","isTrue":"true","explanation":"Wombats haben einen speziellen Darm, der wuerfelfoermige Hinterlassenschaften formt, damit sie nicht wegrollen."},"en":{"statement":"Wombats produce cube-shaped poop.","isTrue":"true","explanation":"Wombats have a special intestine that forms cube-shaped droppings so they don\\"},"es":{"statement":"Los wombats producen heces con forma de cubo.","isTrue":"true","explanation":"Los wombats tienen un intestino especial que da forma cúbica a sus deposiciones para que no rueden."},"fr":{"statement":"Les wombats produisent des crottes en forme de cube.","isTrue":"true","explanation":"Les wombats ont un intestin spécial qui forme des excréments cubiques pour qu\\"},"it":{"statement":"I vombati producono escrementi a forma di cubo.","isTrue":"true","explanation":"I vombati hanno un intestino speciale che modella le feci a forma di cubo, così non rotolano via."},"nl":{"statement":"Wombats produceren kubusvormige uitwerpselen.","isTrue":"true","explanation":"Wombats hebben een speciaal darmstelsel dat kubusvormige uitwerpselen vormt, zodat ze niet wegrollen."},"pl":{"statement":"Wombaty produkują sześcienne odchody.","isTrue":"true","explanation":"Wombaty mają specjalny układ trawienny, który formuje sześcienne odchody, żeby się nie toczyły."},"pt":{"statement":"Os vombates produzem fezes em forma de cubo.","isTrue":"true","explanation":"Os vombates têm um intestino especial que forma fezes cúbicas para que não rolem."},"tr":{"statement":"Vombatlar küp şeklinde dışkı üretir.","isTrue":"true","explanation":"Vombatların özel bir bağırsak yapısı vardır ve küp biçimli dışkı üretir, böylece yuvarlanmaz."},"ar":{"statement":"حيوان الومبت ينتج فضلات مكعبة الشكل.","isTrue":"true","explanation":"لدى الومبت أمعاء خاصة تُشكّل فضلات مكعبة حتى لا تتدحرج."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Eiffelturm ist im Winter kleiner als im Sommer.","isTrue":"true","explanation":"Durch die Kälte zieht sich das Metall zusammen, wodurch der Turm bis zu 15 cm schrumpft."},"en":{"statement":"The Eiffel Tower is shorter in winter than in summer.","isTrue":"true","explanation":"The cold causes the metal to contract, making the tower shrink by up to 15 cm."},"es":{"statement":"La Torre Eiffel es más baja en invierno que en verano.","isTrue":"true","explanation":"Con el frío, el metal se contrae, haciendo que la torre encoja hasta 15 cm."},"fr":{"statement":"La tour Eiffel est plus petite en hiver qu\\","isTrue":"true","explanation":"Avec le froid, le métal se contracte, faisant rétrécir la tour jusqu\\"},"it":{"statement":"La Torre Eiffel è più bassa in inverno che in estate.","isTrue":"true","explanation":"Con il freddo, il metallo si contrae, facendo restringere la torre fino a 15 cm."},"nl":{"statement":"De Eiffeltoren is in de winter kleiner dan in de zomer.","isTrue":"true","explanation":"Door de kou krimpt het metaal samen, waardoor de toren tot 15 cm krimpt."},"pl":{"statement":"Wieża Eiffla jest zimą mniejsza niż latem.","isTrue":"true","explanation":"Z powodu zimna metal się kurczy, przez co wieża zmniejsza się nawet o 15 cm."},"pt":{"statement":"A Torre Eiffel é mais pequena no inverno do que no verão.","isTrue":"true","explanation":"Com o frio, o metal contrai-se, fazendo a torre encolher até 15 cm."},"tr":{"statement":"Eyfel Kulesi kışın yazdan daha kısadır.","isTrue":"true","explanation":"Soğukta metal büzüşür ve kule 15 cm\\"},"ar":{"statement":"برج إيفل أقصر في الشتاء منه في الصيف.","isTrue":"true","explanation":"بسبب البرودة ينكمش المعدن، مما يجعل البرج أقصر بحوالي 15 سم."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Kühe haben vier Maegen.","isTrue":"true","explanation":"Kühe haben tatsächlich vier Maegenabschnitte: Pansen, Netzmagen, Blaettermagen und Labmagen."},"en":{"statement":"Cows have four stomachs.","isTrue":"true","explanation":"Cows actually have four stomach compartments: the rumen, reticulum, omasum, and abomasum."},"es":{"statement":"Las vacas tienen cuatro estómagos.","isTrue":"true","explanation":"Las vacas tienen cuatro compartimentos estomacales: rumen, retículo, omaso y abomaso."},"fr":{"statement":"Les vaches ont quatre estomacs.","isTrue":"true","explanation":"Les vaches ont quatre compartiments stomacaux : la panse, le bonnet, le feuillet et la caillette."},"it":{"statement":"Le mucche hanno quattro stomaci.","isTrue":"true","explanation":"Le mucche hanno quattro compartimenti dello stomaco: rumine, reticolo, omaso e abomaso."},"nl":{"statement":"Koeien hebben vier magen.","isTrue":"true","explanation":"Koeien hebben inderdaad vier maagafdelingen: pens, netmaag, boekmaag en lebmaag."},"pl":{"statement":"Krowy mają cztery żołądki.","isTrue":"true","explanation":"Krowy mają rzeczywiście cztery komory żołądka: żwacz, czepiec, księgi i trawieniec."},"pt":{"statement":"As vacas têm quatro estômagos.","isTrue":"true","explanation":"As vacas têm de facto quatro compartimentos estomacais: rúmen, retículo, omaso e abomaso."},"tr":{"statement":"İneklerin dört midesi vardır.","isTrue":"true","explanation":"İneklerin gerçekten dört mide bölümü vardır: işkembe, börkenek, kırkbayır ve şirden."},"ar":{"statement":"الأبقار لديها أربع معدات.","isTrue":"true","explanation":"للأبقار فعلاً أربعة أقسام للمعدة: الكرش، والشبكية، والورقية، والأنفحة."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Ein Strauss kann schneller laufen als ein Pferd.","isTrue":"true","explanation":"Strausse können bis zu 70 km/h erreichen, während Pferde maximal 65 km/h schaffen."},"en":{"statement":"An ostrich can run faster than a horse.","isTrue":"true","explanation":"Ostriches can reach speeds of up to 70 km/h, while horses max out at about 65 km/h."},"es":{"statement":"Un avestruz puede correr más rápido que un caballo.","isTrue":"true","explanation":"Los avestruces pueden alcanzar hasta 70 km/h, mientras que los caballos llegan a un máximo de 65 km/h."},"fr":{"statement":"Une autruche peut courir plus vite qu\\","isTrue":"true","explanation":"Les autruches peuvent atteindre 70 km/h, alors que les chevaux atteignent un maximum de 65 km/h."},"it":{"statement":"Uno struzzo può correre più veloce di un cavallo.","isTrue":"true","explanation":"Gli struzzi possono raggiungere i 70 km/h, mentre i cavalli arrivano al massimo a 65 km/h."},"nl":{"statement":"Een struisvogel kan sneller rennen dan een paard.","isTrue":"true","explanation":"Struisvogels kunnen tot 70 km/u halen, terwijl paarden maximaal 65 km/u bereiken."},"pl":{"statement":"Struś może biegać szybciej niż koń.","isTrue":"true","explanation":"Strusie mogą osiągać prędkość do 70 km/h, podczas gdy konie maksymalnie 65 km/h."},"pt":{"statement":"Uma avestruz pode correr mais rápido do que um cavalo.","isTrue":"true","explanation":"As avestruzes podem atingir até 70 km/h, enquanto os cavalos chegam no máximo a 65 km/h."},"tr":{"statement":"Bir devekuşu attan daha hızlı koşabilir.","isTrue":"true","explanation":"Devekuşları saatte 70 km\\"},"ar":{"statement":"النعامة تستطيع الركض أسرع من الحصان.","isTrue":"true","explanation":"تصل سرعة النعام إلى 70 كم/ساعة، بينما الخيول تصل إلى 65 كم/ساعة كحد أقصى."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Die Erde dreht sich schneller als vor einer Million Jahren.","isTrue":"false","explanation":"Die Erde dreht sich langsamer. Durch die Gezeitenkraefte des Mondes werden die Tage länger."},"en":{"statement":"The Earth spins faster now than it did a million years ago.","isTrue":"false","explanation":"The Earth is actually slowing down. Tidal forces from the Moon are making the days longer."},"es":{"statement":"La Tierra gira más rápido que hace un millón de años.","isTrue":"false","explanation":"La Tierra gira más lento. Debido a las fuerzas de marea de la Luna, los días se hacen más largos."},"fr":{"statement":"La Terre tourne plus vite qu\\","isTrue":"false","explanation":"La Terre tourne plus lentement. En raison des forces de marée de la Lune, les jours s\\"},"it":{"statement":"La Terra ruota più velocemente rispetto a un milione di anni fa.","isTrue":"false","explanation":"La Terra ruota più lentamente. A causa delle forze di marea della Luna, i giorni si allungano."},"nl":{"statement":"De aarde draait sneller dan een miljoen jaar geleden.","isTrue":"false","explanation":"De aarde draait langzamer. Door de getijdenkrachten van de maan worden de dagen langer."},"pl":{"statement":"Ziemia obraca się szybciej niż milion lat temu.","isTrue":"false","explanation":"Ziemia obraca się wolniej. Z powodu sił pływowych Księżyca dni stają się dłuższe."},"pt":{"statement":"A Terra gira mais rápido do que há um milhão de anos.","isTrue":"false","explanation":"A Terra gira mais devagar. Devido às forças de maré da Lua, os dias estão a ficar mais longos."},"tr":{"statement":"Dünya bir milyon yıl öncesine göre daha hızlı dönüyor.","isTrue":"false","explanation":"Dünya daha yavaş dönüyor. Ay\\"},"ar":{"statement":"الأرض تدور أسرع مما كانت عليه قبل مليون سنة.","isTrue":"false","explanation":"الأرض تدور أبطأ. بسبب قوى المد والجزر للقمر تصبح الأيام أطول."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Venedig hat mehr Brücken als Amsterdam.","isTrue":"false","explanation":"Amsterdam hat über1.500 Brücken, Venedig nur etwa 400."},"en":{"statement":"Venice has more bridges than Amsterdam.","isTrue":"false","explanation":"Amsterdam has over 1,500 bridges, while Venice has only about 400."},"es":{"statement":"Venecia tiene más puentes que Ámsterdam.","isTrue":"false","explanation":"Ámsterdam tiene más de 1.500 puentes, Venecia solo unos 400."},"fr":{"statement":"Venise a plus de ponts qu\\","isTrue":"false","explanation":"Amsterdam a plus de 1 500 ponts, Venise seulement environ 400."},"it":{"statement":"Venezia ha più ponti di Amsterdam.","isTrue":"false","explanation":"Amsterdam ha oltre 1.500 ponti, Venezia solo circa 400."},"nl":{"statement":"Venetië heeft meer bruggen dan Amsterdam.","isTrue":"false","explanation":"Amsterdam heeft meer dan 1.500 bruggen, Venetië slechts ongeveer 400."},"pl":{"statement":"Wenecja ma więcej mostów niż Amsterdam.","isTrue":"false","explanation":"Amsterdam ma ponad 1500 mostów, Wenecja jedynie ok. 400."},"pt":{"statement":"Veneza tem mais pontes do que Amesterdão.","isTrue":"false","explanation":"Amesterdão tem mais de 1.500 pontes, Veneza apenas cerca de 400."},"tr":{"statement":"Venedik\\","isTrue":"false","explanation":"Amsterdam\\"},"ar":{"statement":"البندقية لديها جسور أكثر من أمستردام.","isTrue":"false","explanation":"أمستردام لديها أكثر من 1,500 جسر، بينما البندقية لديها حوالي 400 فقط."}}', 'medium', 'Geografie', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Amazonas mündet ins Meer ohne eine einzige Brücke.","isTrue":"true","explanation":"Es gibt keine Brücke überden gesamten Amazonas — er fließt durch zu dichten Regenwald."},"en":{"statement":"The Amazon flows into the sea without a single bridge crossing it.","isTrue":"true","explanation":"There is no bridge spanning the entire Amazon — it flows through dense rainforest."},"es":{"statement":"El Amazonas desemboca en el mar sin un solo puente.","isTrue":"true","explanation":"No hay ningún puente que cruce todo el Amazonas — fluye a través de selva tropical demasiado densa."},"fr":{"statement":"L\\","isTrue":"true","explanation":"Il n\\"},"it":{"statement":"Il Rio delle Amazzoni sfocia nel mare senza un solo ponte.","isTrue":"true","explanation":"Non esiste alcun ponte che attraversi l\\"},"nl":{"statement":"De Amazone mondt uit in zee zonder ook maar één brug.","isTrue":"true","explanation":"Er is geen enkele brug over de gehele Amazone — hij stroomt door te dicht regenwoud."},"pl":{"statement":"Amazonka wpada do morza bez ani jednego mostu.","isTrue":"true","explanation":"Nie istnieje żaden most na całej Amazonce — płynie przez zbyt gęstą dżunglę."},"pt":{"statement":"O Amazonas desagua no mar sem uma única ponte.","isTrue":"true","explanation":"Não existe nenhuma ponte em toda a extensão do Amazonas — ele flui por floresta tropical demasiado densa."},"tr":{"statement":"Amazon, üzerinde tek bir köprü olmadan denize dökülür.","isTrue":"true","explanation":"Amazon Nehri\\"},"ar":{"statement":"نهر الأمازون يصب في البحر دون أي جسر واحد.","isTrue":"true","explanation":"لا يوجد أي جسر يعبر نهر الأمازون بأكمله — فهو يجري عبر غابات مطيرة كثيفة جداً."}}', 'medium', 'Geografie', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Bienen können Gesichter erkennen.","isTrue":"true","explanation":"Studien zeigen, dass Honigbienen menschliche Gesichter unterscheiden und wiedererkennen können."},"en":{"statement":"Bees can recognize human faces.","isTrue":"true","explanation":"Studies show that honeybees can distinguish and remember human faces."},"es":{"statement":"Las abejas pueden reconocer rostros.","isTrue":"true","explanation":"Estudios demuestran que las abejas melíferas pueden distinguir y reconocer rostros humanos."},"fr":{"statement":"Les abeilles peuvent reconnaître les visages.","isTrue":"true","explanation":"Des études montrent que les abeilles mellifères peuvent distinguer et reconnaître les visages humains."},"it":{"statement":"Le api possono riconoscere i volti.","isTrue":"true","explanation":"Studi dimostrano che le api mellifere possono distinguere e riconoscere i volti umani."},"nl":{"statement":"Bijen kunnen gezichten herkennen.","isTrue":"true","explanation":"Studies tonen aan dat honingbijen menselijke gezichten kunnen onderscheiden en herkennen."},"pl":{"statement":"Pszczoły potrafią rozpoznawać twarze.","isTrue":"true","explanation":"Badania wykazują, że pszczoły miodne potrafią rozróżniać i rozpoznawać ludzkie twarze."},"pt":{"statement":"As abelhas conseguem reconhecer rostos.","isTrue":"true","explanation":"Estudos mostram que as abelhas conseguem distinguir e reconhecer rostos humanos."},"tr":{"statement":"Arılar yüzleri tanıyabilir.","isTrue":"true","explanation":"Araştırmalar, bal arılarının insan yüzlerini ayırt edebildiğini ve tanıyabildiğini göstermektedir."},"ar":{"statement":"النحل يستطيع التعرف على الوجوه.","isTrue":"true","explanation":"تُظهر الدراسات أن نحل العسل يمكنه تمييز الوجوه البشرية والتعرف عليها."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Mars hat den höchsten Berg im Sonnensystem.","isTrue":"true","explanation":"Olympus Mons auf dem Mars ist mit etwa 22 km der höchste bekannte Berg im Sonnensystem."},"en":{"statement":"Mars has the tallest mountain in the solar system.","isTrue":"true","explanation":"Olympus Mons on Mars, at about 22 km high, is the tallest known mountain in the solar system."},"es":{"statement":"Marte tiene la montaña más alta del sistema solar.","isTrue":"true","explanation":"El Olympus Mons en Marte, con unos 22 km, es la montaña más alta conocida del sistema solar."},"fr":{"statement":"Mars possède la plus haute montagne du système solaire.","isTrue":"true","explanation":"L\\"},"it":{"statement":"Marte ha la montagna più alta del sistema solare.","isTrue":"true","explanation":"L\\"},"nl":{"statement":"Mars heeft de hoogste berg in het zonnestelsel.","isTrue":"true","explanation":"Olympus Mons op Mars is met ongeveer 22 km de hoogste bekende berg in het zonnestelsel."},"pl":{"statement":"Mars ma najwyższą górę w Układzie Słonecznym.","isTrue":"true","explanation":"Olympus Mons na Marsie ma ok. 22 km wysokości i jest najwyższą znaną górą w Układzie Słonecznym."},"pt":{"statement":"Marte tem a montanha mais alta do Sistema Solar.","isTrue":"true","explanation":"O Olympus Mons em Marte, com cerca de 22 km, é a montanha mais alta conhecida no Sistema Solar."},"tr":{"statement":"Mars, Güneş Sistemi\\","isTrue":"true","explanation":"Mars\\"},"ar":{"statement":"المريخ يحتوي على أعلى جبل في المجموعة الشمسية.","isTrue":"true","explanation":"أوليمبوس مونس على المريخ بارتفاع حوالي 22 كم هو أعلى جبل معروف في المجموعة الشمسية."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Schokolade ist fürHunde giftig.","isTrue":"true","explanation":"Theobromin in Schokolade kann fürHunde tödlich sein, da sie es nicht abbauen können."},"en":{"statement":"Chocolate is poisonous to dogs.","isTrue":"true","explanation":"Theobromine in chocolate can be lethal to dogs because they can''t metabolize it."},"es":{"statement":"El chocolate es tóxico para los perros.","isTrue":"true","explanation":"La teobromina del chocolate puede ser mortal para los perros, ya que no pueden metabolizarla."},"fr":{"statement":"Le chocolat est toxique pour les chiens.","isTrue":"true","explanation":"La théobromine dans le chocolat peut être mortelle pour les chiens, car ils ne peuvent pas la métaboliser."},"it":{"statement":"Il cioccolato è tossico per i cani.","isTrue":"true","explanation":"La teobromina nel cioccolato può essere letale per i cani, poiché non riescono a metabolizzarla."},"nl":{"statement":"Chocolade is giftig voor honden.","isTrue":"true","explanation":"Theobromine in chocolade kan dodelijk zijn voor honden, omdat ze het niet kunnen afbreken."},"pl":{"statement":"Czekolada jest trująca dla psów.","isTrue":"true","explanation":"Teobromina w czekoladzie może być śmiertelna dla psów, ponieważ nie potrafią jej metabolizować."},"pt":{"statement":"O chocolate é tóxico para os cães.","isTrue":"true","explanation":"A teobromina no chocolate pode ser fatal para os cães, pois eles não conseguem metabolizá-la."},"tr":{"statement":"Çikolata köpekler için zehirlidir.","isTrue":"true","explanation":"Çikolatadaki teobromin köpekler için ölümcül olabilir çünkü onu metabolize edemezler."},"ar":{"statement":"الشوكولاتة سامة للكلاب.","isTrue":"true","explanation":"مادة الثيوبرومين في الشوكولاتة يمكن أن تكون قاتلة للكلاب لأنها لا تستطيع تفكيكها."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"In Australien verlieren Baeume keine Blaetter, sondern ihre Rinde.","isTrue":"true","explanation":"Viele Eukalyptusarten werfen ihre Rinde ab statt ihrer Blaetter."},"en":{"statement":"In Australia, trees don''t shed their leaves — they shed their bark.","isTrue":"true","explanation":"Many eucalyptus species shed their bark instead of their leaves."},"es":{"statement":"En Australia los árboles no pierden hojas, sino corteza.","isTrue":"true","explanation":"Muchas especies de eucalipto mudan su corteza en lugar de sus hojas."},"fr":{"statement":"En Australie, les arbres ne perdent pas leurs feuilles, mais leur écorce.","isTrue":"true","explanation":"De nombreuses espèces d\\"},"it":{"statement":"In Australia gli alberi non perdono le foglie, ma la corteccia.","isTrue":"true","explanation":"Molte specie di eucalipto perdono la corteccia invece delle foglie."},"nl":{"statement":"In Australië verliezen bomen niet hun bladeren, maar hun bast.","isTrue":"true","explanation":"Veel eucalyptussoorten werpen hun bast af in plaats van hun bladeren."},"pl":{"statement":"W Australii drzewa nie zrzucają liści, lecz korę.","isTrue":"true","explanation":"Wiele gatunków eukaliptusa zrzuca korę zamiast liści."},"pt":{"statement":"Na Austrália, as árvores não perdem as folhas, mas sim a casca.","isTrue":"true","explanation":"Muitas espécies de eucalipto largam a casca em vez das folhas."},"tr":{"statement":"Avustralya\\","isTrue":"true","explanation":"Birçok okaliptüs türü yaprakları yerine kabuklarını döker."},"ar":{"statement":"في أستراليا الأشجار لا تسقط أوراقها بل لحاءها.","isTrue":"true","explanation":"كثير من أنواع الكينا تسقط لحاءها بدلاً من أوراقها."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Das Herz einer Garnele sitzt im Kopf.","isTrue":"true","explanation":"Das Herz einer Garnele befindet sich tatsächlich in ihrem Kopf."},"en":{"statement":"A shrimp''s heart is located in its head.","isTrue":"true","explanation":"A shrimp''s heart is indeed located in its head."},"es":{"statement":"El corazón de una gamba está en su cabeza.","isTrue":"true","explanation":"El corazón de una gamba se encuentra efectivamente en su cabeza."},"fr":{"statement":"Le cœur d\\","isTrue":"true","explanation":"Le cœur d\\"},"it":{"statement":"Il cuore di un gambero si trova nella testa.","isTrue":"true","explanation":"Il cuore di un gambero si trova effettivamente nella sua testa."},"nl":{"statement":"Het hart van een garnaal zit in zijn hoofd.","isTrue":"true","explanation":"Het hart van een garnaal bevindt zich daadwerkelijk in zijn hoofd."},"pl":{"statement":"Serce krewetki znajduje się w jej głowie.","isTrue":"true","explanation":"Serce krewetki faktycznie znajduje się w jej głowie."},"pt":{"statement":"O coração de um camarão fica na cabeça.","isTrue":"true","explanation":"O coração de um camarão encontra-se de facto na sua cabeça."},"tr":{"statement":"Karidessin kalbi başındadır.","isTrue":"true","explanation":"Bir karidesin kalbi gerçekten başında yer alır."},"ar":{"statement":"قلب الروبيان يقع في رأسه.","isTrue":"true","explanation":"قلب الروبيان يوجد فعلاً في رأسه."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Vatikan hat die höchste Kriminalitaetsrate der Welt pro Kopf.","isTrue":"true","explanation":"Da der Vatikan nur etwa 800 Einwohner hat, fuehren wenige Straftaten zu einer hohen Pro-Kopf-Rate."},"en":{"statement":"The Vatican has the highest crime rate per capita in the world.","isTrue":"true","explanation":"Since the Vatican has only about 800 residents, even a few crimes result in a high per-capita rate."},"es":{"statement":"El Vaticano tiene la tasa de criminalidad per cápita más alta del mundo.","isTrue":"true","explanation":"Como el Vaticano solo tiene unos 800 habitantes, unos pocos delitos generan una alta tasa per cápita."},"fr":{"statement":"Le Vatican a le taux de criminalité par habitant le plus élevé au monde.","isTrue":"true","explanation":"Comme le Vatican ne compte qu\\"},"it":{"statement":"Il Vaticano ha il tasso di criminalità pro capite più alto del mondo.","isTrue":"true","explanation":"Poiché il Vaticano ha solo circa 800 abitanti, pochi reati generano un alto tasso pro capite."},"nl":{"statement":"Het Vaticaan heeft het hoogste misdaadcijfer ter wereld per hoofd van de bevolking.","isTrue":"true","explanation":"Aangezien het Vaticaan slechts ongeveer 800 inwoners heeft, leiden weinig misdrijven tot een hoog per-capita-cijfer."},"pl":{"statement":"Watykan ma najwyższy wskaźnik przestępczości na świecie per capita.","isTrue":"true","explanation":"Ponieważ Watykan liczy tylko ok. 800 mieszkańców, nawet nieliczne przestępstwa dają wysoki wskaźnik per capita."},"pt":{"statement":"O Vaticano tem a maior taxa de criminalidade do mundo per capita.","isTrue":"true","explanation":"Como o Vaticano tem apenas cerca de 800 habitantes, poucos crimes resultam numa taxa per capita elevada."},"tr":{"statement":"Vatikan, kişi başına düşen suç oranı bakımından dünyanın en yüksek değerine sahiptir.","isTrue":"true","explanation":"Vatikan\\"},"ar":{"statement":"الفاتيكان لديه أعلى معدل جريمة في العالم للفرد الواحد.","isTrue":"true","explanation":"بما أن الفاتيكان يضم حوالي 800 مقيم فقط، فإن جرائم قليلة تؤدي إلى معدل مرتفع للفرد."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Ein Mensch kann im Weltraum überleben, wenn er die Luft anhaelt.","isTrue":"false","explanation":"Im Vakuum würde die Luft aus den Lungen gewaltsam herausgezogen. Man würde ca. 15 Sekunden bewusstlos."},"en":{"statement":"A person can survive in space by holding their breath.","isTrue":"false","explanation":"In a vacuum, air would be violently pulled from your lungs. You would lose consciousness in about 15 seconds."},"es":{"statement":"Una persona puede sobrevivir en el espacio si contiene la respiración.","isTrue":"false","explanation":"En el vacío, el aire sería expulsado de los pulmones con fuerza. Se perdería la consciencia en unos 15 segundos."},"fr":{"statement":"Un humain peut survivre dans l\\","isTrue":"false","explanation":"Dans le vide, l\\"},"it":{"statement":"Un essere umano può sopravvivere nello spazio trattenendo il respiro.","isTrue":"false","explanation":"Nel vuoto, l\\"},"nl":{"statement":"Een mens kan in de ruimte overleven als hij zijn adem inhoudt.","isTrue":"false","explanation":"In een vacuüm zou de lucht met geweld uit de longen worden gezogen. Je zou binnen ca. 15 seconden bewusteloos raken."},"pl":{"statement":"Człowiek może przeżyć w kosmosie, jeśli wstrzyma oddech.","isTrue":"false","explanation":"W próżni powietrze zostałoby siłą wyciągnięte z płuc. Stracisz przytomność w ok. 15 sekund."},"pt":{"statement":"Um ser humano pode sobreviver no espaço se suster a respiração.","isTrue":"false","explanation":"No vácuo, o ar seria arrancado dos pulmões com força. Ficaria inconsciente em cerca de 15 segundos."},"tr":{"statement":"Bir insan nefesini tutarsa uzayda hayatta kalabilir.","isTrue":"false","explanation":"Boşlukta hava ciğerlerden zorla çekilir. Yaklaşık 15 saniyede bilincini kaybedersiniz."},"ar":{"statement":"يستطيع الإنسان البقاء حياً في الفضاء إذا حبس أنفاسه.","isTrue":"false","explanation":"في الفراغ سيُسحب الهواء بقوة من الرئتين. ستفقد الوعي في حوالي 15 ثانية."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Papier kann maximal 7 Mal gefaltet werden.","isTrue":"false","explanation":"Obwohl es schwierig ist, wurde Papier bereits 12 Mal gefaltet (mit ausreichend großem Blatt)."},"en":{"statement":"Paper can only be folded a maximum of 7 times.","isTrue":"false","explanation":"Although difficult, paper has been folded 12 times (with a large enough sheet)."},"es":{"statement":"El papel solo se puede doblar un máximo de 7 veces.","isTrue":"false","explanation":"Aunque es difícil, el papel ya se ha doblado 12 veces (con una hoja suficientemente grande)."},"fr":{"statement":"On ne peut plier un papier que 7 fois maximum.","isTrue":"false","explanation":"Bien que ce soit difficile, du papier a déjà été plié 12 fois (avec une feuille suffisamment grande)."},"it":{"statement":"La carta può essere piegata al massimo 7 volte.","isTrue":"false","explanation":"Anche se è difficile, la carta è già stata piegata 12 volte (con un foglio sufficientemente grande)."},"nl":{"statement":"Papier kan maximaal 7 keer gevouwen worden.","isTrue":"false","explanation":"Hoewel het moeilijk is, is papier al 12 keer gevouwen (met een groot genoeg vel)."},"pl":{"statement":"Papier można złożyć maksymalnie 7 razy.","isTrue":"false","explanation":"Choć jest to trudne, papier został już złożony 12 razy (przy wystarczająco dużym arkuszu)."},"pt":{"statement":"O papel só pode ser dobrado no máximo 7 vezes.","isTrue":"false","explanation":"Embora seja difícil, o papel já foi dobrado 12 vezes (com uma folha suficientemente grande)."},"tr":{"statement":"Kâğıt en fazla 7 kez katlanabilir.","isTrue":"false","explanation":"Zor olsa da kâğıt zaten 12 kez katlanmıştır (yeterince büyük bir kâğıtla)."},"ar":{"statement":"لا يمكن طي الورق أكثر من 7 مرات.","isTrue":"false","explanation":"على الرغم من صعوبة ذلك، تم طي الورق 12 مرة بالفعل (بورقة كبيرة بما يكفي)."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Die Große Mauer Chinas ist über21.000 km lang.","isTrue":"true","explanation":"Mit allen Nebenmauern und Verzweigungen misst sie insgesamt 21.196 km."},"en":{"statement":"The Great Wall of China is over 21,000 km long.","isTrue":"true","explanation":"Including all branches and secondary walls, it measures a total of 21,196 km."},"es":{"statement":"La Gran Muralla China tiene más de 21.000 km de longitud.","isTrue":"true","explanation":"Con todas las murallas secundarias y ramificaciones, mide un total de 21.196 km."},"fr":{"statement":"La Grande Muraille de Chine fait plus de 21 000 km de long.","isTrue":"true","explanation":"Avec toutes les murailles secondaires et ramifications, elle mesure au total 21 196 km."},"it":{"statement":"La Grande Muraglia cinese è lunga più di 21.000 km.","isTrue":"true","explanation":"Con tutte le mura secondarie e le diramazioni, misura in totale 21.196 km."},"nl":{"statement":"De Chinese Muur is meer dan 21.000 km lang.","isTrue":"true","explanation":"Met alle zijmuren en vertakkingen meet hij in totaal 21.196 km."},"pl":{"statement":"Wielki Mur Chiński ma ponad 21 000 km długości.","isTrue":"true","explanation":"Ze wszystkimi bocznymi murami i odgałęzieniami mierzy łącznie 21 196 km."},"pt":{"statement":"A Grande Muralha da China tem mais de 21.000 km de comprimento.","isTrue":"true","explanation":"Com todas as muralhas laterais e ramificações, mede um total de 21.196 km."},"tr":{"statement":"Çin Seddi 21.000 km\\","isTrue":"true","explanation":"Tüm yan duvarları ve dallanmalarıyla birlikte toplam 21.196 km uzunluğundadır."},"ar":{"statement":"سور الصين العظيم يزيد طوله عن 21,000 كم.","isTrue":"true","explanation":"مع جميع الجدران الجانبية والتفرعات يبلغ طوله الإجمالي 21,196 كم."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Finnland hat mehr Saunas als Autos.","isTrue":"true","explanation":"Finnland hat ca. 3,3 Millionen Saunas bei 5,5 Millionen Einwohnern — das ist mehr als Autos."},"en":{"statement":"Finland has more saunas than cars.","isTrue":"true","explanation":"Finland has about 3.3 million saunas for 5.5 million people — more than the number of cars."},"es":{"statement":"Finlandia tiene más saunas que coches.","isTrue":"true","explanation":"Finlandia tiene aprox. 3,3 millones de saunas para 5,5 millones de habitantes — más que coches."},"fr":{"statement":"La Finlande a plus de saunas que de voitures.","isTrue":"true","explanation":"La Finlande compte environ 3,3 millions de saunas pour 5,5 millions d\\"},"it":{"statement":"La Finlandia ha più saune che automobili.","isTrue":"true","explanation":"La Finlandia ha circa 3,3 milioni di saune per 5,5 milioni di abitanti — più delle automobili."},"nl":{"statement":"Finland heeft meer sauna\\","isTrue":"true","explanation":"Finland heeft ca. 3,3 miljoen sauna\\"},"pl":{"statement":"Finlandia ma więcej saun niż samochodów.","isTrue":"true","explanation":"Finlandia ma ok. 3,3 miliona saun przy 5,5 miliona mieszkańców — to więcej niż samochodów."},"pt":{"statement":"A Finlândia tem mais saunas do que automóveis.","isTrue":"true","explanation":"A Finlândia tem cerca de 3,3 milhões de saunas para 5,5 milhões de habitantes — mais do que automóveis."},"tr":{"statement":"Finlandiya\\","isTrue":"true","explanation":"Finlandiya\\"},"ar":{"statement":"في فنلندا عدد حمامات الساونا أكثر من عدد السيارات.","isTrue":"true","explanation":"لدى فنلندا حوالي 3.3 مليون ساونا لـ 5.5 مليون نسمة — وهذا أكثر من السيارات."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Ein Blauwal-Herz ist so groß wie ein Kleinwagen.","isTrue":"true","explanation":"Das Herz eines Blauwals kann bis zu 600 kg wiegen und ist so groß wie ein VW Kaefer."},"en":{"statement":"A blue whale''s heart is the size of a small car.","isTrue":"true","explanation":"A blue whale''s heart can weigh up to 600 kg and is roughly the size of a VW Beetle."},"es":{"statement":"El corazón de una ballena azul es tan grande como un coche pequeño.","isTrue":"true","explanation":"El corazón de una ballena azul puede pesar hasta 600 kg y es tan grande como un Volkswagen Escarabajo."},"fr":{"statement":"Le cœur d\\","isTrue":"true","explanation":"Le cœur d\\"},"it":{"statement":"Il cuore di una balenottera azzurra è grande quanto un\\","isTrue":"true","explanation":"Il cuore di una balenottera azzurra può pesare fino a 600 kg ed è grande quanto un Maggiolino Volkswagen."},"nl":{"statement":"Een blauwwalhart is zo groot als een kleine auto.","isTrue":"true","explanation":"Het hart van een blauwe vinvis kan tot 600 kg wegen en is zo groot als een VW Kever."},"pl":{"statement":"Serce płetwala błękitnego jest wielkości małego samochodu.","isTrue":"true","explanation":"Serce płetwala błękitnego może ważyć do 600 kg i jest wielkości VW Garbusa."},"pt":{"statement":"O coração de uma baleia-azul é do tamanho de um carro pequeno.","isTrue":"true","explanation":"O coração de uma baleia-azul pode pesar até 600 kg e é do tamanho de um VW Carocha."},"tr":{"statement":"Mavi balinanın kalbi küçük bir araba büyüklüğündedir.","isTrue":"true","explanation":"Mavi balinanın kalbi 600 kg\\"},"ar":{"statement":"قلب الحوت الأزرق بحجم سيارة صغيرة.","isTrue":"true","explanation":"يمكن أن يزن قلب الحوت الأزرق حتى 600 كغ وهو بحجم سيارة فولكس فاجن بيتل."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Die Sonne ist gelb.","isTrue":"false","explanation":"Die Sonne ist eigentlich weiss. Sie erscheint uns gelb durch die Atmosphaere der Erde."},"en":{"statement":"The Sun is yellow.","isTrue":"false","explanation":"The Sun is actually white. It appears yellow to us because of Earth''s atmosphere."},"es":{"statement":"El sol es amarillo.","isTrue":"false","explanation":"El sol es en realidad blanco. Nos parece amarillo debido a la atmósfera de la Tierra."},"fr":{"statement":"Le soleil est jaune.","isTrue":"false","explanation":"Le soleil est en réalité blanc. Il nous paraît jaune à cause de l\\"},"it":{"statement":"Il sole è giallo.","isTrue":"false","explanation":"Il sole è in realtà bianco. Ci appare giallo a causa dell\\"},"nl":{"statement":"De zon is geel.","isTrue":"false","explanation":"De zon is eigenlijk wit. Ze lijkt ons geel door de atmosfeer van de aarde."},"pl":{"statement":"Słońce jest żółte.","isTrue":"false","explanation":"Słońce jest w rzeczywistości białe. Wydaje nam się żółte z powodu atmosfery Ziemi."},"pt":{"statement":"O Sol é amarelo.","isTrue":"false","explanation":"O Sol é na verdade branco. Parece-nos amarelo devido à atmosfera da Terra."},"tr":{"statement":"Güneş sarıdır.","isTrue":"false","explanation":"Güneş aslında beyazdır. Dünya\\"},"ar":{"statement":"الشمس صفراء اللون.","isTrue":"false","explanation":"الشمس في الواقع بيضاء. تبدو لنا صفراء بسبب الغلاف الجوي للأرض."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Fische können ertrinken.","isTrue":"true","explanation":"Wenn zu wenig Sauerstoff im Wasser ist, können Fische tatsächlich ersticken."},"en":{"statement":"Fish can drown.","isTrue":"true","explanation":"If there is too little oxygen in the water, fish can indeed suffocate."},"es":{"statement":"Los peces pueden ahogarse.","isTrue":"true","explanation":"Si hay muy poco oxígeno en el agua, los peces pueden asfixiarse."},"fr":{"statement":"Les poissons peuvent se noyer.","isTrue":"true","explanation":"S\\"},"it":{"statement":"I pesci possono annegare.","isTrue":"true","explanation":"Se c\\"},"nl":{"statement":"Vissen kunnen verdrinken.","isTrue":"true","explanation":"Als er te weinig zuurstof in het water is, kunnen vissen daadwerkelijk stikken."},"pl":{"statement":"Ryby mogą się utopić.","isTrue":"true","explanation":"Gdy w wodzie jest zbyt mało tlenu, ryby mogą rzeczywiście się udusić."},"pt":{"statement":"Os peixes podem afogar-se.","isTrue":"true","explanation":"Quando há pouco oxigénio na água, os peixes podem efetivamente sufocar."},"tr":{"statement":"Balıklar boğulabilir.","isTrue":"true","explanation":"Suda yeterli oksijen olmadığında balıklar gerçekten boğulabilir."},"ar":{"statement":"الأسماك يمكن أن تغرق.","isTrue":"true","explanation":"عندما يكون الأكسجين قليلاً في الماء، يمكن أن تختنق الأسماك فعلاً."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Mount Everest waechst jedes Jahr um etwa 4 Millimeter.","isTrue":"true","explanation":"Durch tektonische Plattenbewegungen waechst der Himalaya immer noch."},"en":{"statement":"Mount Everest grows about 4 millimeters every year.","isTrue":"true","explanation":"Due to tectonic plate movement, the Himalayas are still growing."},"es":{"statement":"El Monte Everest crece unos 4 milímetros al año.","isTrue":"true","explanation":"Debido al movimiento de las placas tectónicas, el Himalaya sigue creciendo."},"fr":{"statement":"Le Mont Everest grandit d\\","isTrue":"true","explanation":"En raison du mouvement des plaques tectoniques, l\\"},"it":{"statement":"Il Monte Everest cresce di circa 4 millimetri all\\","isTrue":"true","explanation":"A causa del movimento delle placche tettoniche, l\\"},"nl":{"statement":"De Mount Everest groeit elk jaar ongeveer 4 millimeter.","isTrue":"true","explanation":"Door tektonische plaatbewegingen groeit de Himalaya nog steeds."},"pl":{"statement":"Mount Everest rośnie co roku o około 4 milimetry.","isTrue":"true","explanation":"Dzięki ruchom płyt tektonicznych Himalaje wciąż rosną."},"pt":{"statement":"O Monte Evereste cresce cerca de 4 milímetros por ano.","isTrue":"true","explanation":"Devido aos movimentos das placas tectónicas, os Himalaias continuam a crescer."},"tr":{"statement":"Everest Dağı her yıl yaklaşık 4 milimetre yükselir.","isTrue":"true","explanation":"Tektonik plaka hareketleri sayesinde Himalayalar hâlâ yükselmektedir."},"ar":{"statement":"جبل إيفرست يرتفع كل عام حوالي 4 ملليمترات.","isTrue":"true","explanation":"بسبب حركة الصفائح التكتونية لا تزال جبال الهيمالايا تنمو."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Ketchup wurde im 19. Jahrhundert als Medizin verkauft.","isTrue":"true","explanation":"In den 1830er Jahren wurde Tomatenketchup als Heilmittel gegen Durchfall verkauft."},"en":{"statement":"Ketchup was sold as medicine in the 19th century.","isTrue":"true","explanation":"In the 1830s, tomato ketchup was marketed as a remedy for diarrhea."},"es":{"statement":"El kétchup se vendía como medicina en el siglo XIX.","isTrue":"true","explanation":"En la década de 1830, el kétchup de tomate se vendía como remedio contra la diarrea."},"fr":{"statement":"Le ketchup était vendu comme médicament au XIXe siècle.","isTrue":"true","explanation":"Dans les années 1830, le ketchup de tomate était vendu comme remède contre la diarrhée."},"it":{"statement":"Il ketchup veniva venduto come medicina nel XIX secolo.","isTrue":"true","explanation":"Negli anni 1830, il ketchup di pomodoro veniva venduto come rimedio contro la diarrea."},"nl":{"statement":"Ketchup werd in de 19e eeuw als medicijn verkocht.","isTrue":"true","explanation":"In de jaren 1830 werd tomatenketchup verkocht als middel tegen diarree."},"pl":{"statement":"Keczup był w XIX wieku sprzedawany jako lekarstwo.","isTrue":"true","explanation":"W latach 30. XIX wieku keczup pomidorowy był sprzedawany jako środek na biegunkę."},"pt":{"statement":"O ketchup era vendido como medicamento no século XIX.","isTrue":"true","explanation":"Na década de 1830, o ketchup de tomate era vendido como remédio contra a diarreia."},"tr":{"statement":"Ketçap 19. yüzyılda ilaç olarak satılıyordu.","isTrue":"true","explanation":"1830\\"},"ar":{"statement":"الكاتشب كان يُباع كدواء في القرن التاسع عشر.","isTrue":"true","explanation":"في ثلاثينيات القرن التاسع عشر كان كاتشب الطماطم يُباع كعلاج للإسهال."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der kuerzeste Flug der Welt dauert 57 Sekunden.","isTrue":"true","explanation":"Der Flug zwischen Westray und Papa Westray in Schottland dauert nur knapp eine Minute."},"en":{"statement":"The shortest flight in the world lasts 57 seconds.","isTrue":"true","explanation":"The flight between Westray and Papa Westray in Scotland takes just under a minute."},"es":{"statement":"El vuelo más corto del mundo dura 57 segundos.","isTrue":"true","explanation":"El vuelo entre Westray y Papa Westray en Escocia dura apenas un minuto."},"fr":{"statement":"Le vol le plus court du monde dure 57 secondes.","isTrue":"true","explanation":"Le vol entre Westray et Papa Westray en Écosse dure à peine une minute."},"it":{"statement":"Il volo più breve del mondo dura 57 secondi.","isTrue":"true","explanation":"Il volo tra Westray e Papa Westray in Scozia dura appena un minuto."},"nl":{"statement":"De kortste vlucht ter wereld duurt 57 seconden.","isTrue":"true","explanation":"De vlucht tussen Westray en Papa Westray in Schotland duurt slechts een minuut."},"pl":{"statement":"Najkrótszy lot na świecie trwa 57 sekund.","isTrue":"true","explanation":"Lot między Westray a Papa Westray w Szkocji trwa niecałą minutę."},"pt":{"statement":"O voo mais curto do mundo dura 57 segundos.","isTrue":"true","explanation":"O voo entre Westray e Papa Westray, na Escócia, dura pouco mais de um minuto."},"tr":{"statement":"Dünyanın en kısa uçuşu 57 saniye sürer.","isTrue":"true","explanation":"İskoçya\\"},"ar":{"statement":"أقصر رحلة طيران في العالم تستغرق 57 ثانية.","isTrue":"true","explanation":"الرحلة بين ويستراي وبابا ويستراي في اسكتلندا تستغرق دقيقة واحدة فقط."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Oktopusse haben drei Gehirne.","isTrue":"false","explanation":"Oktopusse haben neun Gehirne — ein zentrales und ein zusaetzliches in jedem der acht Arme."},"en":{"statement":"Octopuses have three brains.","isTrue":"false","explanation":"Octopuses actually have nine brains — one central brain and an additional one in each of their eight arms."},"es":{"statement":"Los pulpos tienen tres cerebros.","isTrue":"false","explanation":"Los pulpos tienen nueve cerebros — uno central y uno adicional en cada uno de los ocho brazos."},"fr":{"statement":"Les pieuvres ont trois cerveaux.","isTrue":"false","explanation":"Les pieuvres ont neuf cerveaux — un central et un supplémentaire dans chacun des huit bras."},"it":{"statement":"I polpi hanno tre cervelli.","isTrue":"false","explanation":"I polpi hanno nove cervelli — uno centrale e uno aggiuntivo in ciascuno degli otto tentacoli."},"nl":{"statement":"Octopussen hebben drie hersenen.","isTrue":"false","explanation":"Octopussen hebben negen hersenen — één centraal brein en een extra in elk van de acht armen."},"pl":{"statement":"Ośmiornice mają trzy mózgi.","isTrue":"false","explanation":"Ośmiornice mają dziewięć mózgów — jeden centralny i dodatkowy w każdym z ośmiu ramion."},"pt":{"statement":"Os polvos têm três cérebros.","isTrue":"false","explanation":"Os polvos têm nove cérebros — um central e um adicional em cada um dos oito braços."},"tr":{"statement":"Ahtapotların üç beyni vardır.","isTrue":"false","explanation":"Ahtapotların dokuz beyni vardır — bir merkezi beyin ve sekiz kolun her birinde birer ek beyin."},"ar":{"statement":"الأخطبوط لديه ثلاثة أدمغة.","isTrue":"false","explanation":"الأخطبوط لديه تسعة أدمغة — واحد مركزي وواحد إضافي في كل ذراع من أذرعه الثمانية."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Brasilien ist nach einem Baum benannt.","isTrue":"true","explanation":"Brasilien ist nach dem Brasilholz (Pau-Brasil) benannt, das dort reichlich vorkommt."},"en":{"statement":"Brazil is named after a tree.","isTrue":"true","explanation":"Brazil is named after the Brazilwood tree (Pau-Brasil), which was abundant there."},"es":{"statement":"Brasil lleva el nombre de un árbol.","isTrue":"true","explanation":"Brasil recibe su nombre del palo brasil (Pau-Brasil), abundante en la zona."},"fr":{"statement":"Le Brésil tient son nom d\\","isTrue":"true","explanation":"Le Brésil tire son nom du bois de brésil (Pau-Brasil), abondant dans la région."},"it":{"statement":"Il Brasile prende il nome da un albero.","isTrue":"true","explanation":"Il Brasile prende il nome dal legno di brasile (Pau-Brasil), abbondante nella zona."},"nl":{"statement":"Brazilië is vernoemd naar een boom.","isTrue":"true","explanation":"Brazilië is vernoemd naar het brazilhout (Pau-Brasil), dat daar veelvuldig voorkwam."},"pl":{"statement":"Brazylia jest nazwana od drzewa.","isTrue":"true","explanation":"Brazylia jest nazwana od drzewa brazylijskiego (Pau-Brasil), które tam obficie rosło."},"pt":{"statement":"O Brasil tem o nome de uma árvore.","isTrue":"true","explanation":"O Brasil foi nomeado por causa do pau-brasil, que era abundante na região."},"tr":{"statement":"Brezilya adını bir ağaçtan almıştır.","isTrue":"true","explanation":"Brezilya, bölgede bol miktarda bulunan brezilya ağacından (Pau-Brasil) adını almıştır."},"ar":{"statement":"البرازيل سُميت على اسم شجرة.","isTrue":"true","explanation":"البرازيل سُميت على اسم شجرة خشب البرازيل (Pau-Brasil) التي كانت تنمو بكثرة هناك."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Ein Kolibri kann rückwärts fliegen.","isTrue":"true","explanation":"Kolibris sind die einzigen Vögel, die tatsächlich rückwärts fliegen können."},"en":{"statement":"A hummingbird can fly backwards.","isTrue":"true","explanation":"Hummingbirds are the only birds that can truly fly backwards."},"es":{"statement":"Un colibrí puede volar hacia atrás.","isTrue":"true","explanation":"Los colibríes son las únicas aves que realmente pueden volar hacia atrás."},"fr":{"statement":"Un colibri peut voler en arrière.","isTrue":"true","explanation":"Les colibris sont les seuls oiseaux qui peuvent réellement voler en arrière."},"it":{"statement":"Un colibrì può volare all\\","isTrue":"true","explanation":"I colibrì sono gli unici uccelli che possono davvero volare all\\"},"nl":{"statement":"Een kolibrie kan achteruit vliegen.","isTrue":"true","explanation":"Kolibries zijn de enige vogels die daadwerkelijk achteruit kunnen vliegen."},"pl":{"statement":"Koliber potrafi latać do tyłu.","isTrue":"true","explanation":"Kolibry są jedynymi ptakami, które potrafią faktycznie latać do tyłu."},"pt":{"statement":"Um colibri consegue voar para trás.","isTrue":"true","explanation":"Os colibris são as únicas aves que conseguem de facto voar para trás."},"tr":{"statement":"Sinek kuşu geriye doğru uçabilir.","isTrue":"true","explanation":"Sinek kuşları gerçekten geriye doğru uçabilen tek kuşlardır."},"ar":{"statement":"الطائر الطنان يستطيع الطيران للخلف.","isTrue":"true","explanation":"الطيور الطنانة هي الطيور الوحيدة التي تستطيع فعلاً الطيران للخلف."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Die Nase waechst das ganze Leben lang.","isTrue":"true","explanation":"Nase und Ohren hören nie auf zu wachsen, da sie aus Knorpel bestehen."},"en":{"statement":"Your nose keeps growing your entire life.","isTrue":"true","explanation":"The nose and ears never stop growing because they are made of cartilage."},"es":{"statement":"La nariz crece durante toda la vida.","isTrue":"true","explanation":"La nariz y las orejas nunca dejan de crecer, ya que están hechas de cartílago."},"fr":{"statement":"Le nez grandit tout au long de la vie.","isTrue":"true","explanation":"Le nez et les oreilles ne cessent jamais de grandir, car ils sont faits de cartilage."},"it":{"statement":"Il naso cresce per tutta la vita.","isTrue":"true","explanation":"Il naso e le orecchie non smettono mai di crescere, poiché sono fatti di cartilagine."},"nl":{"statement":"De neus groeit je hele leven lang.","isTrue":"true","explanation":"Neus en oren houden nooit op met groeien, omdat ze uit kraakbeen bestaan."},"pl":{"statement":"Nos rośnie przez całe życie.","isTrue":"true","explanation":"Nos i uszy nigdy nie przestają rosnąć, ponieważ składają się z chrząstki."},"pt":{"statement":"O nariz cresce a vida inteira.","isTrue":"true","explanation":"O nariz e as orelhas nunca param de crescer, pois são feitos de cartilagem."},"tr":{"statement":"Burun ömür boyu büyümeye devam eder.","isTrue":"true","explanation":"Burun ve kulaklar kıkırdaktan oluştuğu için büyümeyi asla bırakmazlar."},"ar":{"statement":"الأنف يستمر في النمو طوال الحياة.","isTrue":"true","explanation":"الأنف والأذنان لا يتوقفان عن النمو أبداً لأنهما مصنوعان من الغضروف."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"In Japan ist es ueblich, in der Badewanne zu essen.","isTrue":"false","explanation":"In Japan wird das Bad als Ort der Reinigung betrachtet. Essen darin wäre unueblich."},"en":{"statement":"In Japan, it is common to eat in the bathtub.","isTrue":"false","explanation":"In Japan, the bath is considered a place of cleanliness. Eating in it would be unusual."},"es":{"statement":"En Japón es habitual comer en la bañera.","isTrue":"false","explanation":"En Japón el baño se considera un lugar de purificación. Comer en él sería inusual."},"fr":{"statement":"Au Japon, il est courant de manger dans la baignoire.","isTrue":"false","explanation":"Au Japon, le bain est considéré comme un lieu de purification. Y manger serait inhabituel."},"it":{"statement":"In Giappone è normale mangiare nella vasca da bagno.","isTrue":"false","explanation":"In Giappone il bagno è considerato un luogo di purificazione. Mangiare al suo interno sarebbe insolito."},"nl":{"statement":"In Japan is het gebruikelijk om in bad te eten.","isTrue":"false","explanation":"In Japan wordt het bad beschouwd als een plek van reiniging. Eten erin zou ongebruikelijk zijn."},"pl":{"statement":"W Japonii zwyczajowo je się w wannie.","isTrue":"false","explanation":"W Japonii kąpiel jest postrzegana jako miejsce oczyszczenia. Jedzenie w niej byłoby nietypowe."},"pt":{"statement":"No Japão, é costume comer na banheira.","isTrue":"false","explanation":"No Japão, o banho é visto como um lugar de purificação. Comer lá dentro seria invulgar."},"tr":{"statement":"Japonya\\","isTrue":"false","explanation":"Japonya\\"},"ar":{"statement":"في اليابان من المعتاد الأكل في حوض الاستحمام.","isTrue":"false","explanation":"في اليابان يُعتبر الاستحمام مكاناً للتطهر. الأكل فيه سيكون غير معتاد."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der menschliche Magen produziert taeglich etwa 2 Liter Salzsaeure.","isTrue":"true","explanation":"Die Magensaeure ist stark genug, um Metall aufzulösen, wird aber durch Schleimhaut geschuetzt."},"en":{"statement":"The human stomach produces about 2 liters of hydrochloric acid per day.","isTrue":"true","explanation":"Stomach acid is strong enough to dissolve metal, but the stomach lining protects it."},"es":{"statement":"El estómago humano produce unos 2 litros de ácido clorhídrico al día.","isTrue":"true","explanation":"El ácido gástrico es lo suficientemente fuerte como para disolver metal, pero está protegido por la mucosa."},"fr":{"statement":"L\\","isTrue":"true","explanation":"L\\"},"it":{"statement":"Lo stomaco umano produce circa 2 litri di acido cloridrico al giorno.","isTrue":"true","explanation":"L\\"},"nl":{"statement":"De menselijke maag produceert dagelijks ongeveer 2 liter zoutzuur.","isTrue":"true","explanation":"Het maagzuur is sterk genoeg om metaal op te lossen, maar wordt beschermd door slijmvlies."},"pl":{"statement":"Ludzki żołądek produkuje dziennie ok. 2 litry kwasu solnego.","isTrue":"true","explanation":"Kwas żołądkowy jest wystarczająco silny, by rozpuścić metal, ale jest chroniony przez śluzówkę."},"pt":{"statement":"O estômago humano produz diariamente cerca de 2 litros de ácido clorídrico.","isTrue":"true","explanation":"O ácido gástrico é forte o suficiente para dissolver metal, mas é protegido pela mucosa."},"tr":{"statement":"İnsan midesi günde yaklaşık 2 litre hidroklorik asit üretir.","isTrue":"true","explanation":"Mide asidi metali eritecek kadar güçlüdür, ancak mukoza tabakası tarafından korunur."},"ar":{"statement":"تنتج معدة الإنسان يومياً حوالي 2 لتر من حمض الهيدروكلوريك.","isTrue":"true","explanation":"حمض المعدة قوي بما يكفي لإذابة المعدن، لكنه محمي بالغشاء المخاطي."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Es gibt mehr Baeume auf der Erde als Sterne in der Milchstraße.","isTrue":"true","explanation":"Es gibt etwa 3 Billionen Baeume auf der Erde, aber nur 100-400 Milliarden Sterne in der Milchstraße."},"en":{"statement":"There are more trees on Earth than stars in the Milky Way.","isTrue":"true","explanation":"There are about 3 trillion trees on Earth, but only 100-400 billion stars in the Milky Way."},"es":{"statement":"Hay más árboles en la Tierra que estrellas en la Vía Láctea.","isTrue":"true","explanation":"Hay unos 3 billones de árboles en la Tierra, pero solo 100-400 mil millones de estrellas en la Vía Láctea."},"fr":{"statement":"Il y a plus d\\","isTrue":"true","explanation":"Il y a environ 3 billions d\\"},"it":{"statement":"Ci sono più alberi sulla Terra che stelle nella Via Lattea.","isTrue":"true","explanation":"Ci sono circa 3 bilioni di alberi sulla Terra, ma solo 100-400 miliardi di stelle nella Via Lattea."},"nl":{"statement":"Er zijn meer bomen op aarde dan sterren in de Melkweg.","isTrue":"true","explanation":"Er zijn ongeveer 3 biljoen bomen op aarde, maar slechts 100-400 miljard sterren in de Melkweg."},"pl":{"statement":"Na Ziemi jest więcej drzew niż gwiazd w Drodze Mlecznej.","isTrue":"true","explanation":"Na Ziemi jest ok. 3 biliony drzew, ale w Drodze Mlecznej tylko 100-400 miliardów gwiazd."},"pt":{"statement":"Existem mais árvores na Terra do que estrelas na Via Láctea.","isTrue":"true","explanation":"Existem cerca de 3 biliões de árvores na Terra, mas apenas 100-400 mil milhões de estrelas na Via Láctea."},"tr":{"statement":"Dünya\\","isTrue":"true","explanation":"Dünya\\"},"ar":{"statement":"عدد الأشجار على الأرض أكثر من عدد النجوم في مجرة درب التبانة.","isTrue":"true","explanation":"يوجد حوالي 3 تريليون شجرة على الأرض، لكن 100-400 مليار نجمة فقط في درب التبانة."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Die Farbe Orange wurde nach der Frucht benannt, nicht umgekehrt.","isTrue":"true","explanation":"Vor der Orange hiess die Farbe auf Englisch \"geoluhread\" (gelb-rot). Die Frucht gab der Farbe ihren Namen."},"en":{"statement":"The color orange was named after the fruit, not the other way around.","isTrue":"true","explanation":"Before the orange fruit, the color was called \"geoluhread\" (yellow-red) in English. The fruit gave the color its name."},"es":{"statement":"El color naranja recibió su nombre de la fruta, no al revés.","isTrue":"true","explanation":"Antes de la naranja, el color se llamaba en inglés \"geoluhread\" (amarillo-rojo). La fruta le dio el nombre al color."},"fr":{"statement":"La couleur orange a été nommée d\\","isTrue":"true","explanation":"Avant l\\"},"it":{"statement":"Il colore arancione prende il nome dal frutto, non il contrario.","isTrue":"true","explanation":"Prima dell\\"},"nl":{"statement":"De kleur oranje is vernoemd naar de vrucht, niet andersom.","isTrue":"true","explanation":"Vóór de sinaasappel heette de kleur in het Engels \"geoluhread\" (geelrood). De vrucht gaf de kleur haar naam."},"pl":{"statement":"Kolor pomarańczowy został nazwany od owocu, a nie odwrotnie.","isTrue":"true","explanation":"Przed pomarańczą kolor ten w języku angielskim nazywał się \"geoluhread\" (żółto-czerwony). Owoc nadał nazwy kolorowi."},"pt":{"statement":"A cor laranja foi nomeada por causa da fruta, e não o contrário.","isTrue":"true","explanation":"Antes da laranja, a cor chamava-se em inglês \"geoluhread\" (amarelo-vermelho). A fruta deu o nome à cor."},"tr":{"statement":"Turuncu rengi adını meyveden almıştır, tersi değil.","isTrue":"true","explanation":"Portakaldan önce bu renk İngilizce\\"},"ar":{"statement":"لون البرتقالي سُمي على اسم الفاكهة وليس العكس.","isTrue":"true","explanation":"قبل البرتقالة كان هذا اللون يُسمى بالإنجليزية \"geoluhread\" (أصفر-أحمر). الفاكهة أعطت اللون اسمه."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Bananen sind radioaktiv.","isTrue":"true","explanation":"Bananen enthalten Kalium-40, ein radioaktives Isotop. Die Strahlung ist aber völlig harmlos."},"en":{"statement":"Bananas are radioactive.","isTrue":"true","explanation":"Bananas contain potassium-40, a radioactive isotope. However, the radiation is completely harmless."},"es":{"statement":"Los plátanos son radiactivos.","isTrue":"true","explanation":"Los plátanos contienen potasio-40, un isótopo radiactivo. Pero la radiación es completamente inofensiva."},"fr":{"statement":"Les bananes sont radioactives.","isTrue":"true","explanation":"Les bananes contiennent du potassium-40, un isotope radioactif. Mais la radiation est totalement inoffensive."},"it":{"statement":"Le banane sono radioattive.","isTrue":"true","explanation":"Le banane contengono potassio-40, un isotopo radioattivo. Ma la radiazione è completamente innocua."},"nl":{"statement":"Bananen zijn radioactief.","isTrue":"true","explanation":"Bananen bevatten kalium-40, een radioactief isotoop. De straling is echter volkomen onschadelijk."},"pl":{"statement":"Banany są radioaktywne.","isTrue":"true","explanation":"Banany zawierają potas-40, radioaktywny izotop. Promieniowanie jest jednak całkowicie nieszkodliwe."},"pt":{"statement":"As bananas são radioativas.","isTrue":"true","explanation":"As bananas contêm potássio-40, um isótopo radioativo. A radiação é, contudo, totalmente inofensiva."},"tr":{"statement":"Muzlar radyoaktiftir.","isTrue":"true","explanation":"Muzlar radyoaktif bir izotop olan potasyum-40 içerir. Ancak radyasyon tamamen zararsızdır."},"ar":{"statement":"الموز مشع إشعاعياً.","isTrue":"true","explanation":"يحتوي الموز على البوتاسيوم-40، وهو نظير مشع. لكن الإشعاع غير ضار تماماً."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Ein Tag auf dem Pluto dauert länger als eine Woche auf der Erde.","isTrue":"true","explanation":"Ein Pluto-Tag dauert 6,4 Erdtage — also fast eine ganze Erdwoche."},"en":{"statement":"A day on Pluto is longer than a week on Earth.","isTrue":"true","explanation":"A Pluto day lasts 6.4 Earth days — nearly an entire Earth week."},"es":{"statement":"Un día en Plutón dura más que una semana en la Tierra.","isTrue":"true","explanation":"Un día en Plutón dura 6,4 días terrestres — casi una semana terrestre entera."},"fr":{"statement":"Un jour sur Pluton dure plus longtemps qu\\","isTrue":"true","explanation":"Un jour sur Pluton dure 6,4 jours terrestres — presque une semaine terrestre entière."},"it":{"statement":"Un giorno su Plutone dura più di una settimana sulla Terra.","isTrue":"true","explanation":"Un giorno su Plutone dura 6,4 giorni terrestri — quasi un\\"},"nl":{"statement":"Een dag op Pluto duurt langer dan een week op aarde.","isTrue":"true","explanation":"Een Pluto-dag duurt 6,4 aardse dagen — bijna een hele aardse week."},"pl":{"statement":"Dzień na Plutonie trwa dłużej niż tydzień na Ziemi.","isTrue":"true","explanation":"Dzień na Plutonie trwa 6,4 dnia ziemskiego — prawie cały ziemski tydzień."},"pt":{"statement":"Um dia em Plutão dura mais do que uma semana na Terra.","isTrue":"true","explanation":"Um dia em Plutão dura 6,4 dias terrestres — quase uma semana inteira na Terra."},"tr":{"statement":"Plüton\\","isTrue":"true","explanation":"Plüton\\"},"ar":{"statement":"اليوم على بلوتو أطول من أسبوع على الأرض.","isTrue":"true","explanation":"يستغرق اليوم على بلوتو 6.4 يوم أرضي — أي تقريباً أسبوع أرضي كامل."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"In der Schweiz darf man nach 22 Uhr nicht mehr die Toilette spuelen.","isTrue":"false","explanation":"Das ist ein weit verbreiteter Mythos. Es gibt kein solches Gesetz in der Schweiz."},"en":{"statement":"In Switzerland, you''re not allowed to flush the toilet after 10 PM.","isTrue":"false","explanation":"This is a widespread myth. There is no such law in Switzerland."},"es":{"statement":"En Suiza no se puede tirar de la cadena después de las 22 horas.","isTrue":"false","explanation":"Esto es un mito muy extendido. No existe tal ley en Suiza."},"fr":{"statement":"En Suisse, il est interdit de tirer la chasse d\\","isTrue":"false","explanation":"C\\"},"it":{"statement":"In Svizzera non si può tirare lo sciacquone dopo le 22.","isTrue":"false","explanation":"Questo è un mito molto diffuso. Non esiste una legge simile in Svizzera."},"nl":{"statement":"In Zwitserland mag je na 22 uur niet meer doorspoelen.","isTrue":"false","explanation":"Dit is een wijdverbreide mythe. Er bestaat geen dergelijke wet in Zwitserland."},"pl":{"statement":"W Szwajcarii nie wolno spuszczać wody w toalecie po godzinie 22.","isTrue":"false","explanation":"To szeroko rozpowszechniony mit. Takie prawo w Szwajcarii nie istnieje."},"pt":{"statement":"Na Suíça, não se pode puxar o autoclismo depois das 22h.","isTrue":"false","explanation":"Isto é um mito muito difundido. Não existe tal lei na Suíça."},"tr":{"statement":"İsviçre\\","isTrue":"false","explanation":"Bu yaygın bir efsanedir. İsviçre\\"},"ar":{"statement":"في سويسرا يُمنع سحب سيفون المرحاض بعد الساعة العاشرة مساءً.","isTrue":"false","explanation":"هذه أسطورة منتشرة. لا يوجد مثل هذا القانون في سويسرا."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Lachen ist ansteckend, weil das Gehirn Spiegelneuronen aktiviert.","isTrue":"true","explanation":"Spiegelneuronen im Gehirn reagieren auf das Lachen anderer und lösen ähnliche Reaktionen aus."},"en":{"statement":"Laughter is contagious because the brain activates mirror neurons.","isTrue":"true","explanation":"Mirror neurons in the brain respond to other people''s laughter and trigger similar reactions."},"es":{"statement":"La risa es contagiosa porque el cerebro activa las neuronas espejo.","isTrue":"true","explanation":"Las neuronas espejo del cerebro reaccionan a la risa de otros y desencadenan reacciones similares."},"fr":{"statement":"Le rire est contagieux parce que le cerveau active les neurones miroirs.","isTrue":"true","explanation":"Les neurones miroirs du cerveau réagissent au rire des autres et déclenchent des réactions similaires."},"it":{"statement":"La risata è contagiosa perché il cervello attiva i neuroni specchio.","isTrue":"true","explanation":"I neuroni specchio nel cervello reagiscono alla risata altrui e innescano reazioni simili."},"nl":{"statement":"Lachen is besmettelijk doordat de hersenen spiegelneuronen activeren.","isTrue":"true","explanation":"Spiegelneuronen in de hersenen reageren op het lachen van anderen en veroorzaken soortgelijke reacties."},"pl":{"statement":"Śmiech jest zaraźliwy, ponieważ mózg aktywuje neurony lustrzane.","isTrue":"true","explanation":"Neurony lustrzane w mózgu reagują na śmiech innych i wywołują podobne reakcje."},"pt":{"statement":"O riso é contagioso porque o cérebro ativa neurónios-espelho.","isTrue":"true","explanation":"Os neurónios-espelho no cérebro reagem ao riso dos outros e desencadeiam reações semelhantes."},"tr":{"statement":"Gülmek bulaşıcıdır çünkü beyin ayna nöronlarını aktive eder.","isTrue":"true","explanation":"Beyindeki ayna nöronlar başkalarının gülüşüne tepki verir ve benzer tepkilere yol açar."},"ar":{"statement":"الضحك معدٍ لأن الدماغ ينشط الخلايا العصبية المرآتية.","isTrue":"true","explanation":"الخلايا العصبية المرآتية في الدماغ تتفاعل مع ضحك الآخرين وتُحدث ردود فعل مماثلة."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Russland hat eine größere Fläche als Pluto.","isTrue":"true","explanation":"Russland hat 17,1 Mio. km², die Oberfläche von Pluto betraegt nur 16,7 Mio. km²."},"en":{"statement":"Russia has a larger surface area than Pluto.","isTrue":"true","explanation":"Russia covers 17.1 million km\\u00B2, while Pluto''s surface area is only 16.7 million km\\u00B2."},"es":{"statement":"Rusia tiene una superficie mayor que Plutón.","isTrue":"true","explanation":"Rusia tiene 17,1 mill. km², la superficie de Plutón es de solo 16,7 mill. km²."},"fr":{"statement":"La Russie a une superficie plus grande que Pluton.","isTrue":"true","explanation":"La Russie fait 17,1 millions de km², la surface de Pluton n\\"},"it":{"statement":"La Russia ha una superficie più grande di Plutone.","isTrue":"true","explanation":"La Russia ha 17,1 milioni di km², la superficie di Plutone è di soli 16,7 milioni di km²."},"nl":{"statement":"Rusland heeft een groter oppervlak dan Pluto.","isTrue":"true","explanation":"Rusland heeft 17,1 mln. km², het oppervlak van Pluto bedraagt slechts 16,7 mln. km²."},"pl":{"statement":"Rosja ma większą powierzchnię niż Pluton.","isTrue":"true","explanation":"Rosja ma 17,1 mln km², powierzchnia Plutona to zaledwie 16,7 mln km²."},"pt":{"statement":"A Rússia tem uma área maior do que Plutão.","isTrue":"true","explanation":"A Rússia tem 17,1 milhões de km², a superfície de Plutão é de apenas 16,7 milhões de km²."},"tr":{"statement":"Rusya\\","isTrue":"true","explanation":"Rusya 17,1 milyon km² iken Plüton\\"},"ar":{"statement":"مساحة روسيا أكبر من مساحة سطح بلوتو.","isTrue":"true","explanation":"مساحة روسيا 17.1 مليون كم²، بينما مساحة سطح بلوتو 16.7 مليون كم² فقط."}}', 'medium', 'Geografie', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Ein Teelöffel voll Neutronenstern-Material wiegt 6 Milliarden Tonnen.","isTrue":"true","explanation":"Neutronensterne sind so dicht, dass ein Teelöffel ihres Materials Milliarden Tonnen wiegt."},"en":{"statement":"A teaspoon of neutron star material weighs 6 billion tons.","isTrue":"true","explanation":"Neutron stars are so dense that a teaspoon of their material weighs billions of tons."},"es":{"statement":"Una cucharadita de material de estrella de neutrones pesa 6 mil millones de toneladas.","isTrue":"true","explanation":"Las estrellas de neutrones son tan densas que una cucharadita de su material pesa miles de millones de toneladas."},"fr":{"statement":"Une cuillère à café de matière d\\","isTrue":"true","explanation":"Les étoiles à neutrons sont si denses qu\\"},"it":{"statement":"Un cucchiaino di materiale di stella di neutroni pesa 6 miliardi di tonnellate.","isTrue":"true","explanation":"Le stelle di neutroni sono così dense che un cucchiaino del loro materiale pesa miliardi di tonnellate."},"nl":{"statement":"Een theelepel neutronenstermateriaal weegt 6 miljard ton.","isTrue":"true","explanation":"Neutronensterren zijn zo dicht dat een theelepel van hun materiaal miljarden tonnen weegt."},"pl":{"statement":"Łyżeczka materii z gwiazdy neutronowej waży 6 miliardów ton.","isTrue":"true","explanation":"Gwiazdy neutronowe są tak gęste, że łyżeczka ich materii waży miliardy ton."},"pt":{"statement":"Uma colher de chá de material de estrela de neutrões pesa 6 mil milhões de toneladas.","isTrue":"true","explanation":"As estrelas de neutrões são tão densas que uma colher de chá do seu material pesa milhares de milhões de toneladas."},"tr":{"statement":"Bir çay kaşığı nötron yıldızı maddesi 6 milyar ton ağırlığındadır.","isTrue":"true","explanation":"Nötron yıldızları o kadar yoğundur ki bir çay kaşığı maddeleri milyarlarca ton ağırlığındadır."},"ar":{"statement":"ملعقة شاي من مادة نجم نيوتروني تزن 6 مليارات طن.","isTrue":"true","explanation":"النجوم النيوترونية كثيفة جداً لدرجة أن ملعقة شاي من مادتها تزن مليارات الأطنان."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Katzen haben mehr Knochen als Menschen.","isTrue":"true","explanation":"Katzen haben ca. 230 Knochen, Menschen nur 206."},"en":{"statement":"Cats have more bones than humans.","isTrue":"true","explanation":"Cats have about 230 bones, while humans have only 206."},"es":{"statement":"Los gatos tienen más huesos que los humanos.","isTrue":"true","explanation":"Los gatos tienen aprox. 230 huesos, los humanos solo 206."},"fr":{"statement":"Les chats ont plus d\\","isTrue":"true","explanation":"Les chats ont environ 230 os, les humains seulement 206."},"it":{"statement":"I gatti hanno più ossa degli esseri umani.","isTrue":"true","explanation":"I gatti hanno circa 230 ossa, gli esseri umani solo 206."},"nl":{"statement":"Katten hebben meer botten dan mensen.","isTrue":"true","explanation":"Katten hebben ca. 230 botten, mensen slechts 206."},"pl":{"statement":"Koty mają więcej kości niż ludzie.","isTrue":"true","explanation":"Koty mają ok. 230 kości, ludzie tylko 206."},"pt":{"statement":"Os gatos têm mais ossos do que os humanos.","isTrue":"true","explanation":"Os gatos têm cerca de 230 ossos, os humanos apenas 206."},"tr":{"statement":"Kedilerin insanlardan daha fazla kemiği vardır.","isTrue":"true","explanation":"Kedilerin yaklaşık 230 kemiği varken, insanların yalnızca 206 kemiği vardır."},"ar":{"statement":"القطط لديها عظام أكثر من البشر.","isTrue":"true","explanation":"لدى القطط حوالي 230 عظمة، بينما لدى البشر 206 فقط."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Atlantische Ozean wird jedes Jahr breiter.","isTrue":"true","explanation":"Durch Plattentektonik wird der Atlantik jedes Jahr etwa 2,5 cm breiter."},"en":{"statement":"The Atlantic Ocean is getting wider every year.","isTrue":"true","explanation":"Due to plate tectonics, the Atlantic grows about 2.5 cm wider each year."},"es":{"statement":"El Océano Atlántico se hace más ancho cada año.","isTrue":"true","explanation":"Por la tectónica de placas, el Atlántico se ensancha unos 2,5 cm al año."},"fr":{"statement":"L\\","isTrue":"true","explanation":"En raison de la tectonique des plaques, l\\"},"it":{"statement":"L\\","isTrue":"true","explanation":"A causa della tettonica delle placche, l\\"},"nl":{"statement":"De Atlantische Oceaan wordt elk jaar breder.","isTrue":"true","explanation":"Door platentektoniek wordt de Atlantische Oceaan elk jaar ongeveer 2,5 cm breder."},"pl":{"statement":"Ocean Atlantycki co roku się poszerza.","isTrue":"true","explanation":"Dzięki tektonice płyt Atlantyk poszerza się co roku o ok. 2,5 cm."},"pt":{"statement":"O Oceano Atlântico fica mais largo todos os anos.","isTrue":"true","explanation":"Devido à tectónica de placas, o Atlântico alarga-se cerca de 2,5 cm por ano."},"tr":{"statement":"Atlas Okyanusu her yıl genişler.","isTrue":"true","explanation":"Levha tektoniği nedeniyle Atlantik her yıl yaklaşık 2,5 cm genişler."},"ar":{"statement":"المحيط الأطلسي يتسع كل عام.","isTrue":"true","explanation":"بسبب تكتونيات الصفائح يتسع المحيط الأطلسي بحوالي 2.5 سم سنوياً."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"In Norwegen gibt es eine Stadt namens \"Hell\".","isTrue":"true","explanation":"Hell ist ein Ort in der Gemeinde Verdal in Norwegen. Im Winter friert Hell regelmäßig zu."},"en":{"statement":"There is a town in Norway called \"Hell\".","isTrue":"true","explanation":"Hell is a village in the municipality of Verdal in Norway. In winter, Hell regularly freezes over."},"es":{"statement":"En Noruega hay un pueblo que se llama \"Hell\".","isTrue":"true","explanation":"Hell es un lugar en el municipio de Verdal en Noruega. En invierno, Hell se congela regularmente."},"fr":{"statement":"En Norvège, il existe une ville qui s\\","isTrue":"true","explanation":"Hell est un lieu dans la commune de Verdal en Norvège. En hiver, Hell gèle régulièrement."},"it":{"statement":"In Norvegia esiste un paese che si chiama \"Hell\".","isTrue":"true","explanation":"Hell è un luogo nel comune di Verdal in Norvegia. In inverno, Hell gela regolarmente."},"nl":{"statement":"In Noorwegen is er een plaats genaamd \"Hell\".","isTrue":"true","explanation":"Hell is een plaats in de gemeente Verdal in Noorwegen. In de winter vriest Hell regelmatig dicht."},"pl":{"statement":"W Norwegii istnieje miejscowość o nazwie \"Hell\".","isTrue":"true","explanation":"Hell to miejscowość w gminie Verdal w Norwegii. Zimą Hell regularnie zamarza."},"pt":{"statement":"Na Noruega existe uma localidade chamada \"Hell\".","isTrue":"true","explanation":"Hell é uma localidade no município de Verdal, na Noruega. No inverno, Hell congela regularmente."},"tr":{"statement":"Norveç\\","isTrue":"true","explanation":"Hell, Norveç\\"},"ar":{"statement":"في النرويج يوجد مكان اسمه \"Hell\".","isTrue":"true","explanation":"هيل هي بلدة في بلدية فيردال في النرويج. في الشتاء تتجمد هيل بانتظام."}}', 'medium', 'Geografie', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Ameisen können schwimmen.","isTrue":"true","explanation":"Die meisten Ameisenarten können schwimmen und erzeugen kleine Floesse bei Hochwasser."},"en":{"statement":"Ants can swim.","isTrue":"true","explanation":"Most ant species can swim and even form tiny rafts during floods."},"es":{"statement":"Las hormigas pueden nadar.","isTrue":"true","explanation":"La mayoría de las especies de hormigas pueden nadar y forman pequeñas balsas durante las inundaciones."},"fr":{"statement":"Les fourmis savent nager.","isTrue":"true","explanation":"La plupart des espèces de fourmis savent nager et forment de petits radeaux lors des inondations."},"it":{"statement":"Le formiche sanno nuotare.","isTrue":"true","explanation":"La maggior parte delle specie di formiche sa nuotare e forma piccole zattere durante le inondazioni."},"nl":{"statement":"Mieren kunnen zwemmen.","isTrue":"true","explanation":"De meeste mierensoorten kunnen zwemmen en vormen kleine vlotten bij overstromingen."},"pl":{"statement":"Mrówki potrafią pływać.","isTrue":"true","explanation":"Większość gatunków mrówek potrafi pływać i tworzy małe tratwy podczas powodzi."},"pt":{"statement":"As formigas sabem nadar.","isTrue":"true","explanation":"A maioria das espécies de formigas sabe nadar e formam pequenas jangadas durante cheias."},"tr":{"statement":"Karıncalar yüzebilir.","isTrue":"true","explanation":"Çoğu karınca türü yüzebilir ve sel sırasında küçük sallar oluşturur."},"ar":{"statement":"النمل يستطيع السباحة.","isTrue":"true","explanation":"معظم أنواع النمل تستطيع السباحة وتشكل طوافات صغيرة أثناء الفيضانات."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Mensch teilt 60% seiner DNA mit einer Banane.","isTrue":"true","explanation":"Menschen und Bananen teilen tatsächlich etwa 60% identischer Gene."},"en":{"statement":"Humans share 60% of their DNA with bananas.","isTrue":"true","explanation":"Humans and bananas actually share about 60% of identical genes."},"es":{"statement":"Los humanos comparten el 60% de su ADN con un plátano.","isTrue":"true","explanation":"Los humanos y los plátanos comparten efectivamente alrededor del 60% de genes idénticos."},"fr":{"statement":"L\\","isTrue":"true","explanation":"Les humains et les bananes partagent effectivement environ 60% de gènes identiques."},"it":{"statement":"L\\","isTrue":"true","explanation":"Umani e banane condividono effettivamente circa il 60% di geni identici."},"nl":{"statement":"De mens deelt 60% van zijn DNA met een banaan.","isTrue":"true","explanation":"Mensen en bananen delen daadwerkelijk ongeveer 60% identieke genen."},"pl":{"statement":"Człowiek dzieli 60% swojego DNA z bananem.","isTrue":"true","explanation":"Ludzie i banany rzeczywiście dzielą ok. 60% identycznych genów."},"pt":{"statement":"O ser humano partilha 60% do seu ADN com uma banana.","isTrue":"true","explanation":"Humanos e bananas partilham de facto cerca de 60% de genes idênticos."},"tr":{"statement":"İnsan DNA\\","isTrue":"true","explanation":"İnsanlar ve muzlar gerçekten yaklaşık %60 oranında aynı genleri paylaşır."},"ar":{"statement":"يتشارك الإنسان 60% من حمضه النووي مع الموز.","isTrue":"true","explanation":"يتشارك البشر والموز فعلاً في حوالي 60% من الجينات المتطابقة."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Es regnet auf der Venus Schwefelsaeure.","isTrue":"true","explanation":"Die Wolken der Venus bestehen aus Schwefelsaeuretroepfchen, die aber vor dem Boden verdampfen."},"en":{"statement":"It rains sulfuric acid on Venus.","isTrue":"true","explanation":"Venus''s clouds are made of sulfuric acid droplets, though they evaporate before reaching the ground."},"es":{"statement":"En Venus llueve ácido sulfúrico.","isTrue":"true","explanation":"Las nubes de Venus están formadas por gotitas de ácido sulfúrico, que se evaporan antes de llegar al suelo."},"fr":{"statement":"Il pleut de l\\","isTrue":"true","explanation":"Les nuages de Vénus sont composés de gouttelettes d\\"},"it":{"statement":"Su Venere piove acido solforico.","isTrue":"true","explanation":"Le nuvole di Venere sono composte da goccioline di acido solforico, che evaporano prima di raggiungere il suolo."},"nl":{"statement":"Op Venus regent het zwavelzuur.","isTrue":"true","explanation":"De wolken van Venus bestaan uit zwavelzuurdruppels, die echter vóór de grond verdampen."},"pl":{"statement":"Na Wenus pada deszcz z kwasu siarkowego.","isTrue":"true","explanation":"Chmury Wenus składają się z kropelek kwasu siarkowego, które jednak odparowują przed dotarciem do powierzchni."},"pt":{"statement":"Em Vénus chove ácido sulfúrico.","isTrue":"true","explanation":"As nuvens de Vénus são compostas por gotículas de ácido sulfúrico, que evaporam antes de chegar ao solo."},"tr":{"statement":"Venüs\\","isTrue":"true","explanation":"Venüs\\"},"ar":{"statement":"على كوكب الزهرة تمطر حمض الكبريتيك.","isTrue":"true","explanation":"سحب كوكب الزهرة تتكون من قطرات حمض الكبريتيك، لكنها تتبخر قبل الوصول إلى السطح."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Oxford University existierte vor dem Aztekenreich und vor dem Bau von Machu Picchu.","isTrue":"true","explanation":"Oxford begann ab 1096, das Aztekenreich wurde 1428 gegründet, Machu Picchu um 1450 gebaut."},"en":{"statement":"Oxford University existed before the Aztec Empire and before Machu Picchu was built.","isTrue":"true","explanation":"Oxford began around 1096, the Aztec Empire was founded in 1428, and Machu Picchu was built around 1450."},"es":{"statement":"La Universidad de Oxford existía antes del Imperio Azteca y antes de la construcción de Machu Picchu.","isTrue":"true","explanation":"Oxford comenzó a partir de 1096, el Imperio Azteca se fundó en 1428, Machu Picchu se construyó alrededor de 1450."},"fr":{"statement":"L\\","isTrue":"true","explanation":"Oxford a commencé à partir de 1096, l\\"},"it":{"statement":"L\\","isTrue":"true","explanation":"Oxford iniziò a partire dal 1096, l\\"},"nl":{"statement":"De Universiteit van Oxford bestond al vóór het Aztekenrijk en de bouw van Machu Picchu.","isTrue":"true","explanation":"Oxford begon vanaf 1096, het Aztekenrijk werd in 1428 gesticht, Machu Picchu rond 1450 gebouwd."},"pl":{"statement":"Uniwersytet Oksfordzki istniał przed imperium Azteków i przed budową Machu Picchu.","isTrue":"true","explanation":"Oxford zaczął działać w 1096 r., imperium Azteków powstało w 1428 r., Machu Picchu zbudowano ok. 1450 r."},"pt":{"statement":"A Universidade de Oxford existiu antes do Império Asteca e antes da construção de Machu Picchu.","isTrue":"true","explanation":"Oxford começou em 1096, o Império Asteca foi fundado em 1428, Machu Picchu foi construído por volta de 1450."},"tr":{"statement":"Oxford Üniversitesi hem Aztek İmparatorluğu\\","isTrue":"true","explanation":"Oxford 1096\\"},"ar":{"statement":"جامعة أكسفورد كانت موجودة قبل إمبراطورية الأزتك وقبل بناء ماتشو بيتشو.","isTrue":"true","explanation":"بدأت أكسفورد عام 1096، تأسست إمبراطورية الأزتك عام 1428، وبُني ماتشو بيتشو حوالي عام 1450."}}', 'medium', 'Geschichte', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Ein Chamäleon ändert seine Farbe zur Tarnung.","isTrue":"false","explanation":"Chamäleons ändern ihre Farbe hauptsaechlich zur Kommunikation und Temperaturregulierung, nicht zur Tarnung."},"en":{"statement":"A chameleon changes its color for camouflage.","isTrue":"false","explanation":"Chameleons change color mainly for communication and temperature regulation, not for camouflage."},"es":{"statement":"Un camaleón cambia de color para camuflarse.","isTrue":"false","explanation":"Los camaleones cambian de color principalmente para comunicarse y regular su temperatura, no para camuflarse."},"fr":{"statement":"Un caméléon change de couleur pour se camoufler.","isTrue":"false","explanation":"Les caméléons changent de couleur principalement pour communiquer et réguler leur température, pas pour se camoufler."},"it":{"statement":"Un camaleonte cambia colore per mimetizzarsi.","isTrue":"false","explanation":"I camaleonti cambiano colore principalmente per comunicare e regolare la temperatura, non per mimetizzarsi."},"nl":{"statement":"Een kameleon verandert van kleur voor camouflage.","isTrue":"false","explanation":"Kameleons veranderen voornamelijk van kleur voor communicatie en temperatuurregulatie, niet voor camouflage."},"pl":{"statement":"Kameleon zmienia kolor w celach maskujących.","isTrue":"false","explanation":"Kameleony zmieniają kolor głównie w celach komunikacyjnych i regulacji temperatury, a nie maskowania."},"pt":{"statement":"Um camaleão muda de cor para se camuflar.","isTrue":"false","explanation":"Os camaleões mudam de cor principalmente para comunicação e regulação de temperatura, não para camuflagem."},"tr":{"statement":"Bir bukalemun kamuflaj için renk değiştirir.","isTrue":"false","explanation":"Bukalemunlar ağırlıklı olarak iletişim ve sıcaklık düzenlemesi için renk değiştirir, kamuflaj için değil."},"ar":{"statement":"الحرباء تغير لونها للتمويه.","isTrue":"false","explanation":"تغير الحرباء لونها بشكل رئيسي للتواصل وتنظيم درجة الحرارة، وليس للتمويه."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Der Geruch von frisch geschnittenem Gras ist eigentlich ein Notruf der Pflanzen.","isTrue":"true","explanation":"Pflanzen setzen chemische Stoffe frei, wenn sie verletzt werden — der Geruch ist eine Stressreaktion."},"en":{"statement":"The smell of freshly cut grass is actually a distress signal from the plants.","isTrue":"true","explanation":"Plants release chemical compounds when injured — the smell is a stress response."},"es":{"statement":"El olor a hierba recién cortada es en realidad una señal de auxilio de las plantas.","isTrue":"true","explanation":"Las plantas liberan sustancias químicas cuando son heridas — el olor es una reacción de estrés."},"fr":{"statement":"L\\","isTrue":"true","explanation":"Les plantes libèrent des substances chimiques lorsqu\\"},"it":{"statement":"L\\","isTrue":"true","explanation":"Le piante rilasciano sostanze chimiche quando vengono ferite — l\\"},"nl":{"statement":"De geur van vers gemaaid gras is eigenlijk een noodkreet van planten.","isTrue":"true","explanation":"Planten geven chemische stoffen af wanneer ze beschadigd worden — de geur is een stressreactie."},"pl":{"statement":"Zapach świeżo skoszonej trawy to w rzeczywistości sygnał alarmowy roślin.","isTrue":"true","explanation":"Rośliny uwalniają substancje chemiczne, gdy są uszkadzane — zapach jest reakcją stresową."},"pt":{"statement":"O cheiro de relva recém-cortada é na verdade um pedido de socorro das plantas.","isTrue":"true","explanation":"As plantas libertam substâncias químicas quando são danificadas — o cheiro é uma reação de stress."},"tr":{"statement":"Taze biçilmiş çimen kokusu aslında bitkilerin bir acil durum sinyalidir.","isTrue":"true","explanation":"Bitkiler zarar gördüklerinde kimyasal maddeler salgılar — koku bir stres tepkisidir."},"ar":{"statement":"رائحة العشب المقطوع حديثاً هي في الواقع نداء استغاثة من النباتات.","isTrue":"true","explanation":"تطلق النباتات مواد كيميائية عندما تتعرض للأذى — الرائحة هي استجابة للتوتر."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"In Schweden gibt es ein Hotel komplett aus Eis.","isTrue":"true","explanation":"Das Icehotel in Jukkasjaervi wird jeden Winter aus Eis und Schnee neu aufgebaut."},"en":{"statement":"In Sweden, there is a hotel made entirely of ice.","isTrue":"true","explanation":"The Icehotel in Jukkasjarvi is rebuilt every winter from ice and snow."},"es":{"statement":"En Suecia hay un hotel hecho completamente de hielo.","isTrue":"true","explanation":"El Icehotel en Jukkasjärvi se reconstruye cada invierno con hielo y nieve."},"fr":{"statement":"En Suède, il y a un hôtel entièrement fait de glace.","isTrue":"true","explanation":"L\\"},"it":{"statement":"In Svezia c\\","isTrue":"true","explanation":"L\\"},"nl":{"statement":"In Zweden is er een hotel volledig gemaakt van ijs.","isTrue":"true","explanation":"Het Icehotel in Jukkasjärvi wordt elke winter opnieuw opgebouwd uit ijs en sneeuw."},"pl":{"statement":"W Szwecji istnieje hotel całkowicie z lodu.","isTrue":"true","explanation":"Icehotel w Jukkasjärvi jest co zimę budowany na nowo z lodu i śniegu."},"pt":{"statement":"Na Suécia existe um hotel feito inteiramente de gelo.","isTrue":"true","explanation":"O Icehotel em Jukkasjärvi é reconstruído todos os invernos com gelo e neve."},"tr":{"statement":"İsveç\\","isTrue":"true","explanation":"Jukkasjärvi\\"},"ar":{"statement":"في السويد يوجد فندق مصنوع بالكامل من الجليد.","isTrue":"true","explanation":"فندق الجليد في يوكاسيارفي يُعاد بناؤه كل شتاء من الجليد والثلج."}}', 'medium', 'Kurioses', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Spinnen können fliegen.","isTrue":"true","explanation":"Manche Spinnen nutzen \"Ballooning\" — sie lassen sich an Seidenfaeden vom Wind tragen."},"en":{"statement":"Spiders can fly.","isTrue":"true","explanation":"Some spiders use \"ballooning\" — they release silk threads and let the wind carry them."},"es":{"statement":"Las arañas pueden volar.","isTrue":"true","explanation":"Algunas arañas usan el \"ballooning\" — se dejan llevar por el viento con hilos de seda."},"fr":{"statement":"Les araignées peuvent voler.","isTrue":"true","explanation":"Certaines araignées utilisent le \"ballooning\" — elles se laissent porter par le vent grâce à des fils de soie."},"it":{"statement":"I ragni possono volare.","isTrue":"true","explanation":"Alcuni ragni usano il \"ballooning\" — si lasciano trasportare dal vento con fili di seta."},"nl":{"statement":"Spinnen kunnen vliegen.","isTrue":"true","explanation":"Sommige spinnen gebruiken \"ballooning\" — ze laten zich op zijdedraden door de wind meevoeren."},"pl":{"statement":"Pająki potrafią latać.","isTrue":"true","explanation":"Niektóre pająki stosują „ballooning\" — unoszą się na nitkach jedwabiu niesione wiatrem."},"pt":{"statement":"As aranhas conseguem voar.","isTrue":"true","explanation":"Algumas aranhas usam o \"ballooning\" — deixam-se transportar pelo vento em fios de seda."},"tr":{"statement":"Örümcekler uçabilir.","isTrue":"true","explanation":"Bazı örümcekler \"ballooning\" kullanır — ipek iplikleri üzerinde rüzgârla taşınırlar."},"ar":{"statement":"العناكب تستطيع الطيران.","isTrue":"true","explanation":"بعض العناكب تستخدم تقنية \"البالونينغ\" — تطير محمولة بالرياح على خيوط حريرية."}}', 'medium', 'Natur', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Das Licht der Sonne braucht 8 Sekunden bis zur Erde.","isTrue":"false","explanation":"Es dauert etwa 8 Minuten und 20 Sekunden, nicht 8 Sekunden."},"en":{"statement":"Sunlight takes 8 seconds to reach the Earth.","isTrue":"false","explanation":"It takes about 8 minutes and 20 seconds, not 8 seconds."},"es":{"statement":"La luz del sol tarda 8 segundos en llegar a la Tierra.","isTrue":"false","explanation":"Tarda aproximadamente 8 minutos y 20 segundos, no 8 segundos."},"fr":{"statement":"La lumière du soleil met 8 secondes pour atteindre la Terre.","isTrue":"false","explanation":"Il faut environ 8 minutes et 20 secondes, pas 8 secondes."},"it":{"statement":"La luce del sole impiega 8 secondi per raggiungere la Terra.","isTrue":"false","explanation":"Ci vogliono circa 8 minuti e 20 secondi, non 8 secondi."},"nl":{"statement":"Het licht van de zon heeft 8 seconden nodig om de aarde te bereiken.","isTrue":"false","explanation":"Het duurt ongeveer 8 minuten en 20 seconden, niet 8 seconden."},"pl":{"statement":"Światło słoneczne potrzebuje 8 sekund, aby dotrzeć do Ziemi.","isTrue":"false","explanation":"Potrzebuje ok. 8 minut i 20 sekund, nie 8 sekund."},"pt":{"statement":"A luz do Sol demora 8 segundos a chegar à Terra.","isTrue":"false","explanation":"Demora cerca de 8 minutos e 20 segundos, não 8 segundos."},"tr":{"statement":"Güneş ışığının Dünya\\","isTrue":"false","explanation":"Yaklaşık 8 dakika 20 saniye sürer, 8 saniye değil."},"ar":{"statement":"يستغرق ضوء الشمس 8 ثوانٍ للوصول إلى الأرض.","isTrue":"false","explanation":"يستغرق حوالي 8 دقائق و20 ثانية، وليس 8 ثوانٍ."}}', 'medium', 'Wissenschaft', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('fakeorfact', 'fact', '{"de":{"statement":"Ein Pinguin kann höher springen als ein Haus.","isTrue":"true","explanation":"Das ist ein Scherzfakt — Haeuser können gar nicht springen, also gewinnt der Pinguin."},"en":{"statement":"A penguin can jump higher than a house.","isTrue":"true","explanation":"This is a trick fact — houses can''t jump, so the penguin wins by default."},"es":{"statement":"Un pingüino puede saltar más alto que una casa.","isTrue":"true","explanation":"Este es un dato humorístico — las casas no pueden saltar, así que el pingüino gana."},"fr":{"statement":"Un pingouin peut sauter plus haut qu\\","isTrue":"true","explanation":"C\\"},"it":{"statement":"Un pinguino può saltare più in alto di una casa.","isTrue":"true","explanation":"Questo è un fatto umoristico — le case non possono saltare, quindi vince il pinguino."},"nl":{"statement":"Een pinguïn kan hoger springen dan een huis.","isTrue":"true","explanation":"Dit is een grapfeit — huizen kunnen helemaal niet springen, dus wint de pinguïn."},"pl":{"statement":"Pingwin może skoczyć wyżej niż dom.","isTrue":"true","explanation":"To żartobliwy fakt — domy nie potrafią skakać, więc pingwin wygrywa."},"pt":{"statement":"Um pinguim consegue saltar mais alto do que uma casa.","isTrue":"true","explanation":"Isto é um facto humorístico — as casas não conseguem saltar, por isso o pinguim ganha."},"tr":{"statement":"Bir penguen bir evden daha yükseğe zıplayabilir.","isTrue":"true","explanation":"Bu bir şaka gerçektir — evler zıplayamaz, bu yüzden penguen kazanır."},"ar":{"statement":"البطريق يستطيع القفز أعلى من منزل.","isTrue":"true","explanation":"هذه حقيقة فكاهية — المنازل لا تستطيع القفز، لذلك البطريق يفوز."}}', 'medium', 'Kurioses', true);
